INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (1, 1, 'Boltmane', NULL, NULL, 5, NULL, NULL, NULL, 'The more it moves, the more it heats up and the hair tips increasingly glow brighter. At its peak, it becomes so dazzling that you risk blindness if you stare at it directly.', 'https://palworld.fandom.com/wiki/Special:FilePath/Boltmane.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (2, 1, 'Feathered Dragon', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Dragostrophe&#39;s Cousin.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (3, 1, 'Dragostrophe', 'Lord of the Darkness', NULL, 8, NULL, NULL, NULL, 'A silent beast born of the abyss. Thou shall not stand before the beast. Thou shall not heed the beast.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dragostrophe.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (4, 1, 'Dark Mutant', NULL, NULL, 8, NULL, NULL, NULL, 'Some say a beam from a Dark Mutant that has perfected its technique can tear holes into other dimensions. It''s even believed that certain species of pals were born from such phenomena.', 'https://palworld.fandom.com/wiki/Special:FilePath/DarkMutant.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (5, 1, 'Lamball', 'Big Floof', 'When activated, equips to the player and becomes a shield.Sometimes drops Wool when assigned to .', 1, 'Common', 'Small', 3050, 'A walk up a hill tends to end with this Pal tumbling back down. This causes it to become dizzy and unable to move, making it easy to capture and kill. As a result, this Pal has tumbled down to the very bottom of the food chain itself.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lamball.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (6, 2, 'Cattiva', 'The Cat''s Pajamas', 'While in team, Cattiva helps carry supplies, increasing the player''s max carrying capacity by 100. (Does not stack)', 1, 'Common', 'Small', 2760, 'At a glance it appears full of confidence, but it is in fact weak and cowardly. Being toyed with by a Cattiva is in many ways the greatest of disgraces.', 'https://palworld.fandom.com/wiki/Special:FilePath/Cattiva.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (7, 3, 'Chikipi', 'Plump & Juicy', 'Sometimes lays an Egg when assigned to Ranch.', 1, 'Common', 'Small', 3080, 'Extremely weak and far too delicious. It is one of the weakest Pals alongside Lamball. No matter how many are hunted, they just keep appearing.', 'https://palworld.fandom.com/wiki/Special:FilePath/Chikipi.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (8, 4, 'Lifmunk', 'Coward of the Steppe', 'When activated, leaps on top of the player''s head and uses a submachine gun to follow up the players attacks.', 1, 'Verdant', 'Small', 3020, 'Intelligent as a five to seven-year-old human child. It makes a wonderful partner, but there have been more than a few cases where they''ve killed their master after learning to use weapons.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lifmunk.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (9, 5, 'Fuack', 'Rowdy Wave Ripper', 'When activated, Fuack body surfs towards an enemy and slams into them.', 1, 'Damp', 'Small', 2980, 'Using its own body water, this Pal can create waves anywhere. It body surfs when in a hurry, but the resulting speed often ends in a fatal collision.', 'https://palworld.fandom.com/wiki/Special:FilePath/Fuack.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (10, 5, 'Fuack Ignis', 'Runaway Wave Rider', 'When activated, Fuack Ignis surfs towards an enemy and slams into them.', 1, 'Damp', 'Small', 2300, 'With a belly built for friction, this pal sparks flames as it body surfs.But when it gets carried away, it often ends up a rolling fireball.', 'https://palworld.fandom.com/wiki/Special:FilePath/Fuack Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (11, 6, 'Vixy', 'Star of the Steppe', 'Sometimes digs up items from the ground when assigned to Ranch.', 1, 'Common', 'Small', 3060, 'The idol of Palpagos Island. If you bully a Vixy, you best be prepared to become enemies with the whole world.', 'https://palworld.fandom.com/wiki/Special:FilePath/Vixy.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (12, 7, 'Celaray', 'Soaring Skyfish', 'While in party,modifies the performance of the equipped glider. Prevents fall damage and extends the duration of high-speed gliding', 2, 'Damp', 'Small', 2740, 'Riding the wind, this Pal travels where it pleases.Should it find a partner along the way, the encounter will mark its journey''s end.', 'https://palworld.fandom.com/wiki/Special:FilePath/Celaray.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (13, 7, 'Celaray Lux', 'Sky-Swimming Fish', 'While in team, modifies the performance of the equipped glider.Increases speed while gliding for an extended time.', 2, 'Damp', 'Small', 2380, 'Its flashy patterns help it attract a partner.But after a long history of electrocution incidents involving Celaray Lux, yellow-and-black stripes are now seen across the island as a sign of danger.', 'https://palworld.fandom.com/wiki/Special:FilePath/Celaray Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (14, 8, 'Cremis', 'Darling Furball', 'While in team, increases attack power of Neutral Pals. Sometimes drops Wool when assigned to Ranch.', 1, 'Common', 'Small', 2890, 'Compared to Lamball, it has finer wool and a temperament more suited for domestication.However, it has historically always been kept as a pet.Cuteness is considered a virtue.', 'https://palworld.fandom.com/wiki/Special:FilePath/Cremis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (15, 9, 'Croajiro', 'Harakiri Master', 'When activated, Croajiro swells its abdomen and channels its loyalty to build up energy.Climbing on top will propel the player high into the air.', 2, 'Damp', 'Small', 2600, 'Those who disgrace the honor of the herd are forced to take their own life. By piercing their inflated vocal sac with a tree branch, they are blown away into the atmosphere and return to the afterlife.', 'https://palworld.fandom.com/wiki/Special:FilePath/Croajiro.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (16, 9, 'Croajiro Noct', 'Natural Born Killer', 'When activated, Croajiro Noct swells its abodmen and channel its loyalty to build up energy.Climbing on top will propel the player high into the air.While in team, increases the power of Dark Pals.', 2, 'Damp', 'Large', 1860, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Croajiro Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (17, 10, 'Herbil', 'Percussive Maintenance', 'While in team, Herbil uses its healing powers to revive the player when incapacited.', 1, 'Verdant', 'Small', 2630, 'When in doubt, punch it till it works—that’s Herbil''s approach to fixing things.With strength perfectly tuned for humans, sometimes just one punch is enough to restart a stopped heart.', 'https://palworld.fandom.com/wiki/Special:FilePath/Herbil.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (18, 11, 'Teafant', 'Adorable Watering Can', 'When activated, spouts mysterious water that soothes wounds and restores the player''s HP.', 1, 'Damp', 'Small', 3070, 'Large amounts of water pour from what is thought to be its nose, though some say that it is, in fact, just snot. This has sparked a fierce debate among Pal scholars.', 'https://palworld.fandom.com/wiki/Special:FilePath/Teafant.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (19, 12, 'Gumoss', 'Suddenly Transformed', 'While in party,improves logging efficiency by 30% and reduces weight of all types of wood by 40%. (Does not stack)', 1, 'Verdant', 'Small', 2950, 'A strange Pal with a body resembling tree sap. It gradually loses strength if it has nothing to cover its body with, eventually rotting away.', 'https://palworld.fandom.com/wiki/Special:FilePath/Gumoss.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (20, 13, 'Pupperai', 'Zealous Alpha', 'While in party, increases the player''s melee weapon damage by 10%. (Does not stack)', 1, 'Rocky', 'Small', 2930, 'Pupperai territorial disputes begin with a staredown and end in a single, quick strike.Training them to "stay" is risky business, as the "go" command triggers that same attack instinct.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pupperai.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (21, 14, 'Clovee', 'Dubiously Lucky', 'While at a base, increases the Work Suitability Level for all other Base Pals by +1. (Does not stack)', 1, 'Verdant', 'Small', 2970, 'Some individuals once had three or more leaves on their foreheads.Regarded as symbols of good fortune, those with more leaves were heavily hunted, leading the species to evolve fewer leaves over time.', 'https://palworld.fandom.com/wiki/Special:FilePath/Clovee.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (22, 15, 'Jolthog', 'Don''t Touch!', 'When activated, equips Jolthog to the player''s hand. When thrown at an enemy, causes an electrical explosion upon impact.', 1, 'Electric', 'Small', 3030, 'It releases the electricity stored in its body when under attack.The voltage it generates exceeds 10 million volts, making it more lethal than any conventional heavy firearms when thrown.', 'https://palworld.fandom.com/wiki/Special:FilePath/Jolthog.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (23, 15, 'Jolthog Cryst', 'Watch Your Feet!', 'When activated, equips Jolthog Cryst to the player''s hand. When thrown at an enemy, causes an icy explosion upon impact.', 1, 'Frozen', 'Small', 2850, 'It releases the cold air stored in its body when under attack.The frigid blast it radiates is cold enough to freeze the surrounding air and easily pierces through any attacker''s body.', 'https://palworld.fandom.com/wiki/Special:FilePath/Jolthog Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (24, 16, 'Depresso', 'Several Sleepless Nights Later', 'When activated, Depresso drinks a massive amount of energy drinks, causing its movement speed to increase.', 1, 'Dark', 'Small', 3000, 'It has few friends because of the perpetually grouchy look on its face, but it is in fact kindhearted. Some have seen it feeding Vixy who have strayed from their pack.', 'https://palworld.fandom.com/wiki/Special:FilePath/Depresso.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (25, 17, 'Pengullet', 'Ate Too Much', 'When activated, the player equips a Rocket Launcher and fires Pengullet as ammunition. Pengullet explodes on contact and is incapacitated.', 1, 'Damp', 'Small', 2960, 'The feathers of this Pal have all but disappeared, but sadly, its desire to fly has remained as strong as ever. Even now, it tries to fly again in any way it can.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pengullet.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (26, 17, 'Pengullet Lux', 'Had One Too Many', 'When activated, the player equips a Rocket Launcher and fires Pengullet Lux as ammunition. Pengullet Lux explodes on contact and is incapitated.', 1, 'Damp', 'Small', 2490, 'The feathers of this Pal have all but disappeared, and it can no longer fly.Yet its longing for the sky has turned to jealousy— so it harnessed electricity to strike down those who still soar.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pengullet Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (27, 18, 'Penking', 'Pioneer of the Frozen Sea', 'When fighting together, Fire Pals drop more items when defeated.', 4, 'Damp', 'Large', 2070, 'Surprisingly, it is unrelated to Pengullet.However, since this Pal gets pampered as it pleases, for now, it''s doing its best to strut arrogantly.', 'https://palworld.fandom.com/wiki/Special:FilePath/Penking.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (28, 18, 'Penking Lux', 'Pioneer of the Black', 'While fighting together, Water Pals drop more items when defeated.', 4, 'Damp', 'Large', 1850, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Penking Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (29, 19, 'Hoocrates', 'Purveyor of Wisdom', 'While in team, increases attack power of Dark Pals.', 1, 'Dark', 'Small', 2940, '''''Often lost in thought, it sometimes finds it difficult to sleep. "I think, therefore I am."''', 'https://palworld.fandom.com/wiki/Special:FilePath/Hoocrates.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (30, 20, 'Melpaca', 'Pompous Shanks', 'Can be ridden.While in party, increases Kingpaca''s Defense and Movement Speed.Sometimes drops Wool when assigned to Ranch.', 2, 'Common', 'Small', 2720, 'Don''t be fooled by this Pal''s fluffy appearance.A hypersonic kick from one of its long legs may send you flying to the other side of the world.', 'https://palworld.fandom.com/wiki/Special:FilePath/Melpaca.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (31, 21, 'Kingpaca', 'Supreme Fluff Commander', 'Can be ridden. While in team, Kingpaca helps carry supplies, increasing the player''s max carrying capacity.', 4, 'Common', 'Large', 2220, 'Melpaca serve this Pal. Contests between Kingpaca offer up their vassals as a wager. Those seen alone are losers of such contests.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kingpaca.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (32, 21, 'Kingpaca Cryst', 'Azure Fluff Commander', 'Can be ridden. While in team, Kingpaca helps carry supplies, increasing the player''s max carrying capacity.', 4, 'Frozen', 'Huge', 1530, 'With a heart of ice, this Pal is terrible at expressing its emotions.A solitary individual is pitiable, seen as too clumsy in the eyes of a Melpaca.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kingpaca Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (33, 22, 'Daedream', 'Dream Eater', 'While in team, appears near the player. Follows up player attacks with magic bullets.', 1, 'Dark', 'Small', 2910, 'It puts those it is interested in to sleep and shows them an endless stream of happy dreams. Those who fall under its spell are never to wake until death takes them.', 'https://palworld.fandom.com/wiki/Special:FilePath/Daedream.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (34, 23, 'Tanzee', 'Dexterous Primate', 'When activated, Tanzee will mercilessly fire an assault rifle at nearby enemies.', 1, 'Verdant', 'Small', 2900, 'Long ago, this Pal used long objects like tree branches as weapons.After coming into contact with humans, however, it found something slightly more effective: guns.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tanzee.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (35, 23, 'Tanzee Ignis', 'Flame Aficionado', NULL, 1, 'Scorching', 'Small', 2830, 'Its palms have evolved to handle burning objects without getting scorched. When its gun runs out of ammo, it may grab the heated barrel with its bare hands and use it to club its foes.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tanzee Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (36, 24, 'Nox', 'Nighttime Prince', 'When fighting together, applies Dark damage to the player''s attacks.', 1, 'Dark', 'Large', 2920, 'If you find Nox hair in your bedding, you should leave it where it lays and leave immediately.Picking it up is a one-way-ticket to a never ending night.', 'https://palworld.fandom.com/wiki/Special:FilePath/Nox.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (37, 25, 'Flambelle', 'Molten Daughter', 'Sometimes produces Flame Organ when assigned to Ranch.', 2, 'Scorching', 'Small', 2700, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Flambelle.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (38, 26, 'Rooby', 'Chief of the Herd', 'While in team, increases defense of Fire Pals. Does not stack.', 1, 'Scorching', 'Small', 2870, 'Wild Rooby surprisingly never get sick. Eating one piece of charcoal a day, made by burning a branch, is the secret to its eternal health.', 'https://palworld.fandom.com/wiki/Special:FilePath/Rooby.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (39, 27, 'Mau', 'Noble Glimmer', 'Sometimes digs up Gold Coin when assigned to Ranch.', 1, 'Dark', 'Small', 3040, 'Its hard tail does not deteriorate even when cut off.Some believed these severed tails bring good luck, but for the innumerable Mau who were poached as a result, they were anything but.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mau.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (40, 27, 'Mau Cryst', 'Serene Glimmer', 'Sometimes digs up Gold Coin when assigned to Ranch.', 1, 'Frozen', 'Small', 2750, 'Its crystalline tail is beautiful, but shatters when this Pal dies.Some believe it is good luck to raise them, so Mau Cryst in captivity are treated with great care.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mau Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (41, 28, 'Rushoar', 'Woodland Ruffian', 'Can be ridden. Increases efficiency of destroying boulders while mounted.', 1, 'Rocky', 'Small', 2880, 'Being an extremely aggressive Pal, it often picks fights before gauging its opponents'' strength.Though small, its powerful charge can even send boulders flying.', 'https://palworld.fandom.com/wiki/Special:FilePath/Rushoar.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (42, 29, 'Foxparks', 'Revealer of Paths', 'When activated, equips to the player and transforms into a flamethrower.', 1, 'Scorching', 'Small', 2990, 'It is unskilled at controlling fire from the moment it is born and tends to choke on the flames it breathes unintentionally. Foxparks sneezes are one of the leading causes of forest fires.', 'https://palworld.fandom.com/wiki/Special:FilePath/Foxparks.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (43, 29, 'Foxparks Cryst', 'Icy Blossom Voyager', 'When activated, equips to the player and attacks using frigid air.', 1, 'Frozen', 'Small', 2500, 'It is unskilled at controlling cold air from the moment it is born and tends to choke on the frost it breathes unintentionally. When Foxparks Cryst catches a cold, its nasal discharge freezes, making it difficult to breathe and causing it to panic.', 'https://palworld.fandom.com/wiki/Special:FilePath/Foxparks Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (44, 30, 'Killamari', 'Emotionless', 'While in team, can be summoned and used instead of a glider.Can float for long periods of time while gliding.', 2, 'Dark', 'Small', 2770, 'It wraps itself around an enemy''s head, sucking out their insides.Pal mummies are occasionally found, but these are in fact Killamari victims.', 'https://palworld.fandom.com/wiki/Special:FilePath/Killamari.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (45, 30, 'Killamari Primo', 'Devoid of Emotion', 'While in team, modifies the performance of the equipped glider. Enables gentle floating while gliding for an extended time.', 2, 'Common', 'Small', 2540, 'It sinks its fangs into the enemy’s neck, draining every last drop of blood.When two Killamari Primos latch onto each other, they become locked in a relentless struggle—each trying to suck the other dry until one withers away.', 'https://palworld.fandom.com/wiki/Special:FilePath/Killamari Primo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (46, 31, 'Fuddler', 'Underground Explorer', 'When activated, generates subtle vibrations to detect nearby ore.', 2, 'Rocky', 'Small', 2790, 'Its large claws boast of diamond-like hardness. However, sharpening these claws consumes most of its energy, leading it to sometimes spending entire days doing nothing else.', 'https://palworld.fandom.com/wiki/Special:FilePath/Fuddler.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (47, 32, 'Eikthyrdeer', 'Protector of the Herd', 'Can be ridden.Can perform a double jump while mounted.Increases lumbering efficiency by 220%.', 2, 'Common', 'Large', 2710, 'The one who possesses the most impressive antlers becomes the leader of the herd. If their antlers are broken, they become depressed and leave the herd never to be seen again.', 'https://palworld.fandom.com/wiki/Special:FilePath/Eikthyrdeer.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (48, 32, 'Eikthyrdeer Terra', 'Golden Antlers', 'Can be ridden. Can perform a double jump while mounted. Increases efficiency of cutting trees.', 2, 'Rocky', 'Large', 2580, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Eikthyrdeer Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (49, 33, 'Direhowl', 'Hunter of the Steppe', 'Can be ridden.Moves slightly faster than most mounts.', 2, 'Common', 'Small', 2680, 'Long ago Direhowl would hunt alongside humans but over the years this bond faded.', 'https://palworld.fandom.com/wiki/Special:FilePath/Direhowl.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (50, 34, 'Caprity', 'Walking Farm', 'Sometimes drops Red Berries from its back when assigned to Ranch.', 2, 'Verdant', 'Small', 2610, 'The shrub on this pal''s back produces berries as long as it is properly fed. It offers these berries to potential mates, and if the flavor is to their liking, romance blossoms.', 'https://palworld.fandom.com/wiki/Special:FilePath/Caprity.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (51, 34, 'Caprity Noct', 'Tainted Farm', 'Sometimes drops Venom Gland from its back when assigned to Ranch.', 2, 'Dark', 'Small', 1940, 'The berries that grow on its back change flavor according to its emotions.The harsher the environment it grows in, the sweeter the berries become.This is why most Caprity Noct raised in captivity have never known love.', 'https://palworld.fandom.com/wiki/Special:FilePath/Caprity Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (52, 35, 'Swee', 'Curious Floof', 'While in team, Sweepa''s stats will be increased.', 1, 'Frozen', 'Small', 2840, 'Crawling along the ground, it eats microscopic organic matter.After a while, it discharges any substances that provide no nutrition.By using it as a mop for cleaning, everyone wins!', 'https://palworld.fandom.com/wiki/Special:FilePath/Swee.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (53, 36, 'Sweepa', 'King of the Floof', 'While fighting together, stats will increase the more Swee are in your team.', 4, 'Frozen', 'Large', 2150, 'While hibernating, a large number of Swee hide within its voluminous body hair.The most ever recorded is 101.', 'https://palworld.fandom.com/wiki/Special:FilePath/Sweepa.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (54, 37, 'Turtacle', 'Mini Fortress', 'While in team, Turtacle helps carry supplies, decreasing the weight of armor in the player''s inventory.', 3, 'Damp', 'Small', 2410, 'To protect its fragile body, it developed an incredibly tough shell.Unfortunately, it''s utterly defenseless underneath.Even a little tickle could knock it out cold.', 'https://palworld.fandom.com/wiki/Special:FilePath/Turtacle.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (55, 37, 'Turtacle Terra', 'Golden Fortress', 'While in team, Turtacle Terra helps carry supplies, decreasing the weight of armor in the player''s inventory.Also increases attack power of Ground Pals.', 3, 'Damp', 'Small', 1330, 'To protect its fragile body, it developed an incredibly tough shell.With most of its senses concentrated in its limbs and shell, it can’t even tell if someone quietly touches its core.', 'https://palworld.fandom.com/wiki/Special:FilePath/Turtacle Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (56, 38, 'Hangyu', 'Bringer of Luck', 'While in team, can be summoned and used instead of a glider. Carries the player up high while gliding.', 1, 'Rocky', 'Small', 2780, '''''Its gigantic arms can rip apart even iron.'''' ''''As a particularly cruel form of execution, serious criminals would be strung up in a public square, and a Hangyu would rip off the skin from their bones.''''', 'https://palworld.fandom.com/wiki/Special:FilePath/Hangyu.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (57, 38, 'Hangyu Cryst', 'Glacial Harbinger', 'While in team, can be summoned and used instead of a glider. Carries the player up high while gliding.', 1, 'Frozen', 'Small', 2510, 'Its gigantic arms can tear through blocks of ice. There were times when great sinners were tied in the town square and had their hair torn out by as a brutal form of public humiliation.', 'https://palworld.fandom.com/wiki/Special:FilePath/Hangyu Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (58, 39, 'Woolipop', 'Giant Cotton Candy', 'Sometimes drops Cotton Candy when assigned to ranch.', 1, 'Common', 'Small', 2820, 'Its entire body is 18,000 times sweeter than sugar.Carnivorous Pals lured by its scent will find themselves overwhelmed by sweetness and even pass out should they take a bite of this Pal.', 'https://palworld.fandom.com/wiki/Special:FilePath/Woolipop.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (59, 39, 'Woolipop Terra', 'King-Sized Confection', 'Sometimes drops Caramel Cotton Candy when assigned to .While at a base, reduces depletion rate of Base Pals by -15%. (Does not stack)', 1, 'Rocky', 'Small', 2030, 'Its fur emits a sweet smell, but its meat is disgustingly bitter. Carnivorous Pals lured by its scent into taking a bite will find themselves overwhelmed by the foul taste and pass out.', 'https://palworld.fandom.com/wiki/Special:FilePath/Woolipop Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (60, 40, 'Mozzarina', 'Prime Beef', 'Sometimes produces Milk when assigned to ranch.', 2, 'Common', 'Small', 2800, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Mozzarina.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (61, 41, 'Azurobe', 'Lady of the Lake', 'Can be ridden to travel on water. Applies Water damage to the player''s attacks while mounted.', 5, 'Damp', 'Large', 1830, 'This Pal''s white ribbon turns black if doused with impure water. Given its usefulness in detecting poison, this Pal was once overhunted. This past has left them bitter towards humanity.', 'https://palworld.fandom.com/wiki/Special:FilePath/Azurobe.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (62, 41, 'Azurobe Cryst', 'Lady of the Frozen Lake', 'Can be ridden to travel on water.Changes the player''s attack type to Ice while mounted.', 5, 'Frozen', 'Large', 1220, 'This Pal’s white ribbon continuously absorbs heat from its surroundings, yet its temperature remains curiously unchanged.This strange ability once made it a target of relentless hunting, leaving it with a deep mistrust of humans to this day.', 'https://palworld.fandom.com/wiki/Special:FilePath/Azurobe Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (63, 42, 'Sparkit', 'Livewire Tabby', 'While in team, increases attack power of Electric Pals.', 1, 'Electric', 'Small', 3010, 'During the dry season, this Pal is always on the verge of blowing a fuse.Sparks can fly with even the slightest provocation, even amongst allies.', 'https://palworld.fandom.com/wiki/Special:FilePath/Sparkit.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (64, 43, 'Kelpsea', 'Child of the Deep', 'While in team, increases attack power of Water Pals. Sometimes drops Pal Fluids when assigned to Ranch.', 1, 'Damp', 'Small', 2810, 'Its personality changes depending on the quality of the water it was born into. Kelpsea born into polluted waters are generally ill-tempered and quickly become delinquents.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kelpsea.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (65, 43, 'Kelpsea Ignis', 'Child of the Molten Depths', 'While in team, increases attack power of Fire Pals. Sometimes drops Flame Organ when assigned to Ranch.', 1, 'Scorching', 'Small', 2470, 'Its personality changes depending on the temperature of the water it was born into.Kelpsea born in warm waters generally have a passionate, motivated personality.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kelpsea Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (66, 44, 'Ribbuny', 'Heart-Melting Smile', 'While in team, increases attack power of Neutral Pals.While at base, increases work efficiency if working at Weapon Workbench.', 1, 'Common', 'Small', 2860, 'A Pal that''s never without a bright smile.Occasionally, its tentacles get tied up in knots by Cattiva''s pranks.During those moments, its expression turns demonic.', 'https://palworld.fandom.com/wiki/Special:FilePath/Ribbuny.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (67, 44, 'Ribbuny Botan', 'Sparkling Smile', 'While in team, increases attack power of Grass Pals.While at a base, increases the work efficiency if working at .', 1, 'Verdant', 'Small', 2460, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Ribbuny Botan.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (68, 45, 'Jelliette', 'Sunlight Drifter', 'While in team, increases drops from fishing.While Jelliette and Jelliroy are in base, Jelliette''s watering speed is increased.', 3, 'Damp', 'Small', 2650, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Jellyfish Pal.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (69, 46, 'Jellroy', 'Shade Drifter', 'While in team, increases items obtained from salvage.While and Jellroy are in your base, Jellroy''s watering speed is increased.', 3, 'Damp', 'Small', 2590, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Jellroy.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (70, 47, 'Amione', 'Miraculously Close', 'While at a base, increases the Work Suitability Level for all other Base Pals by +1. (Does not stack)', 3, 'Damp', 'Small', 2520, 'If one disappears, another simply shows up to take its place, and life goes on like nothing happened. For Amione, companionship is everything.', 'https://palworld.fandom.com/wiki/Special:FilePath/Animone.webp') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (71, 48, 'Gloopie', 'Trickster of the Sea', 'While fighting together, the capture gauge decreases more slowly in the fishing minigame when the capture bars are not overlapping.', 3, 'Damp', 'Large', 2530, 'Be sure to check your plans for the next day before falling asleep with this Pal.Its suction cups leave marks that look suspiciously like hickeys.One sleepy cuddle session could lead to some truly awkward misunderstandings.', 'https://palworld.fandom.com/wiki/Special:FilePath/Octopus Pal.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (72, 48, 'Gloopie Primo', 'Everyday Trickster', 'While in party, increases Defense of Water Pals by 15%. (Does not stack)', 3, 'Damp', 'Large', 1630, 'Be sure to check your plans for the next day before falling asleep with this Pal. Its suction cups leave marks that look suspiciously like bite marks. One sleepy cuddle session could lead to some truly unnecessary concern.', 'https://palworld.fandom.com/wiki/Special:FilePath/Gloopie Primo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (73, 49, 'Galeclaw', 'Proud Courier', 'While in team, can be summoned and used instead of a glider. Allows you to fire a gun while gliding with this Pal.', 2, 'Common', 'Small', 2570, 'A Pal that can easily take flight even while grasping a human.It is, however, prone to letting go when tired, which has led to the sudden demise of more than a few souls.', 'https://palworld.fandom.com/wiki/Special:FilePath/Galeclaw.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (74, 50, 'Wispaw', 'Adorable Phantom Thief', NULL, 6, 'Dark', 'Large', 2250, 'The ghostly hands behind it embody the souls of all humans who have raised its kind. Lately, they seem to have reached a unanimous consensus to dote on Wispaw.', 'https://palworld.fandom.com/wiki/Special:FilePath/Wispaw.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (75, 51, 'Nitewing', 'Wings of the Firmament', 'Can be ridden as a flying mount.', 2, 'Common', 'Small', 2560, 'It carries newborn Pals to its nest and raises them as a surrogate parent. Once the baby Pal has fattened up, it hunts them.', 'https://palworld.fandom.com/wiki/Special:FilePath/Nitewing.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (76, 52, 'Tombat', 'Trickster', 'When activated, uses ultrasonic waves to detect the location of nearby Pals.', 2, 'Dark', 'Large', 2340, 'Often appears out of the blue to flaunt its prized wings in front of other Pals.Although this appears to be an intimidation tactic, the Pal seems to derive some kind of pleasure from the display.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tombat.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (77, 53, 'Tocotoco', 'Boom or Bust', 'When activated, equips to the player and transforms into an egg launcher.', 2, 'Common', 'Small', 2730, 'A frightening Pal that produces exploding eggs.It often fires these eggs from its rear end as a form of defense, but when spent, the Pal itself explodes.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tocotoco.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (78, 54, 'Univolt', 'Swift Deity', 'Can be ridden. Applies Electric damage to the player''s attacks while mounted.', 3, 'Electric', 'Large', 2270, 'It used to be considered an emissary of the Thunder God, and thus was not hunted by people. However, after witnesses observed one die from a lightning strike, its reverence faded, and it quite literally fell into the role of a workhorse.', 'https://palworld.fandom.com/wiki/Special:FilePath/Univolt.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (79, 54, 'Univolt Cryst', 'Blustery Blizzard Fiend', NULL, 3, 'Frozen', 'Large', 540, 'It used to be considered an emissary of the Winter God, and thus was not hunted by people. However, after witnesses observed one lose its footing on the ice, its reverence faded, and it quite literally slid into the role of a workhorse.', 'https://palworld.fandom.com/wiki/Special:FilePath/Univolt Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (80, 55, 'Gobfin', 'Sea Thug', 'When activated, attacks targeted enemy with a powerful Aqua Gun. While in team, increases player''s attack power.', 2, 'Damp', 'Small', 2550, 'Long ago, it was a giant and powerful aquatic Pal.However, as food became scarce, it evolved to live on land.Since walking requires much energy, it gradually became smaller and is now a small and puny Pal.', 'https://palworld.fandom.com/wiki/Special:FilePath/Gobfin.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (81, 55, 'Gobfin Ignis', 'Volcano Thug', 'When activated, attacks targeted enemy with a powerful Spirit Fire. While in team, increases player''s attack power.', 2, 'Scorching', 'Small', 2430, 'Long ago, it was a giant and powerful aquatic Pal.However, as food became scarce, it evolved to live on land.Since walking burns many calories, it astonishingly awakened its power to control fire!', 'https://palworld.fandom.com/wiki/Special:FilePath/Gobfin Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (82, 56, 'Loupmoon', 'Enraptured by Moonlight', 'When activated, attacks targeted enemy with a powerful Jumping Claw.', 3, 'Dark', 'Small', 2110, 'The horns on its head grow under the moonlight.It doesn''t hate the sun, but its horns itch when sunlight hits them.', 'https://palworld.fandom.com/wiki/Special:FilePath/Loupmoon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (83, 56, 'Loupmoon Cryst', 'Enraptured by the Frozen Moonlight', 'When activated, attacks targeted enemy with a powerful Snow Claw.', 3, 'Frozen', 'Small', 1290, 'The horns on its head are made of a mysterious ice that never melts.Shaved ice made by breaking off a horn is truly exquisite, but both the one who tries it and Loupmoon Cryst end up with a headache.', 'https://palworld.fandom.com/wiki/Special:FilePath/Loupmoon Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (84, 57, 'Cawgnito', 'Shadow-Cloaked Schemer', 'When activated, attacks targeted enemy with a powerful Phantom Peck.', 3, 'Dark', 'Small', 2370, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Cawgnito.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (85, 58, 'Arsox', 'Blazing Brute', 'Can be ridden. Keeps the rider warm in cold environments.', 3, 'Scorching', 'Small', 2320, 'In ancient times, carnivorous Pals pursued them relentlessly.The absurd fury in the cries of Arsox transformed into a raging inferno, which has been passed on to this day.', 'https://palworld.fandom.com/wiki/Special:FilePath/Arsox.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (86, 59, 'Muffly', 'Totally Toasty', 'While in party, increases the capture rate of Pals afflicted with . (Does not stack)', 3, 'Frozen', 'Small', 2480, 'Its soft facial fluff softens any hit, but it cannot groom itself well nor scratch its itches, leaving it in a constant state of mild frustration.', 'https://palworld.fandom.com/wiki/Special:FilePath/Muffly.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (87, 60, 'Bristla', 'Thorny Rose', 'While in team, increases attack power of Grass Pals.', 2, 'Verdant', 'Small', 2690, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Bristla.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (88, 61, 'Cinnamoth', 'Butterfly Promenade', 'When activated, attacks target enemy with Poison Fog.', 2, 'Verdant', 'Small', 2620, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Cinnamoth.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (89, 62, 'Puffolt', 'Sulky Static', 'While at a base, increases the Work Suitability Level for all other Base Pals by +1. (Does not stack)', 3, 'Electric', 'Small', 2360, 'Its fluffy fur absorbs tremendous amounts of water when soaked.Shaking it dry releases a powerful electrical discharge, making bath time together a serious gamble.', 'https://palworld.fandom.com/wiki/Special:FilePath/Puffolt.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (90, 63, 'Elphidran', 'Gentle Sky Dragon', 'Can be ridden as a flying mount. While fighting together, Dark Pals drop more items when defeated.', 3, 'Dragon', 'Large', 2280, 'It possesses a demeanor as pure as its appearance suggests. Perhaps because of this, it is sometimes unable to discern good from evil, often allowing wrongdoers to take advantage of it.', 'https://palworld.fandom.com/wiki/Special:FilePath/Elphidran.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (91, 63, 'Elphidran Aqua', 'Beast of the Tides', 'Can be ridden as a flying mount.While fighting together, Fire Pals drop more items when defeated.', 3, 'Dragon', 'Large', 1640, 'It possesses a demeanor as pure as its appearance suggests. Perhaps because of this, it harbors no ill will in any of its actions and is indifferent even after killing someone.', 'https://palworld.fandom.com/wiki/Special:FilePath/Elphidran Aqua.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (92, 64, 'Vanwyrm', 'Aerial Marauder', 'Can be ridden as a flying mount. Increases damage player deals to enemy weak points while mounted.', 5, 'Scorching', 'Large', 1650, 'The melodies of a flute made from the exoskeleton of a Vanwyrm are said to cross whole mountain ranges.In ages past, such flutes were used to signal an attack.', 'https://palworld.fandom.com/wiki/Special:FilePath/Vanwyrm.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (93, 64, 'Vanwyrm Cryst', 'Marauder of Frozen Skies', 'Can be ridden as a flying mount. Increases damage player deals to enemy weak points while mounted.', 5, 'Frozen', 'Large', 1430, 'The melodies of a flute made from the exoskeleton of a Vanwyrm Cryst are said to cross whole mountain ranges.In ages past, such flutes were used to signal victory in battle.', 'https://palworld.fandom.com/wiki/Special:FilePath/Vanwyrm Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (94, 65, 'Felbat', 'Gloom-Shrouded Bloodsucker', 'While fighting together, grants the player and Felbat the life steal effect which absorbs some of the received damage and restores HP.', 7, 'Dark', 'Large', 1570, 'Attacking from the shadows, this Pal traps its prey within its cloak-like wings.It''s probably best not to know what happens within them, or why the inside of its wings are stained red.', 'https://palworld.fandom.com/wiki/Special:FilePath/Felbat.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (95, 66, 'Vaelet', 'Voice of the Violets', 'While fighting together, Ground Pals drop more items when defeated.', 5, 'Verdant', 'Large', 1480, 'The castle was filled with the king''s favorite flowers.A great battle ensued, and flames approached the castle.Amidst the chaos, the spirit of a flower appeared.- From the fairy tale, "The King''s Flower."', 'https://palworld.fandom.com/wiki/Special:FilePath/Vaelet.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (96, 67, 'Beegarde', 'Captain of the Guard', 'Sometimes drops Honey when assigned to Ranch.While in team, Elizabee''s stats will be increased.', 3, 'Verdant', 'Small', 2350, 'A servant that pledges loyalty to Elizabee.Any that cause harm to the queen are immediately expelled from the hive.It will gladly give its life to protect its queen.', 'https://palworld.fandom.com/wiki/Special:FilePath/Beegarde.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (97, 68, 'Elizabee', 'Empress of the Hive', 'While fighting together, stats will increase the more Beegarde are in your team.', 5, 'Verdant', 'Large', 1790, 'A chosen queen to rule over Beegardes. There is a never ending stream of servants willing to work themselves to death for the pleasure of serving their queen.', 'https://palworld.fandom.com/wiki/Special:FilePath/Elizabee.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (98, 69, 'Lovander', 'Pal on the Prowl', 'While fighting together, grants the player and Lovander the life steal effect which absorbs some of the received damage and restores HP.', 4, 'Dark', 'Large', 2090, 'Seeking a night of love, it is always chasing someone around.At first it only showed interest in other Pals, but in recent years even humans have become the target of its debauchery.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lovander.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (99, 70, 'Grintale', 'Marshmallow Body', 'Can be ridden. Enhances Neutral attacks while mounted.', 4, 'Common', 'Large', 2120, 'Grintale''s eyes light up the moment anyone enters its territory.This is no figure of speech—its eyes literally light up.', 'https://palworld.fandom.com/wiki/Special:FilePath/Grintale.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (100, 71, 'Tarantriss', 'Tactician of the Thread Realm', 'Can be ridden.While mounted, shoots spider silk to grapple and enable rapid movement.', 4, 'Dark', 'Small', 1730, 'Extremely sticky and clingy.The more it''s resisted, the more tenacious it becomes.Such is its "personality."', 'https://palworld.fandom.com/wiki/Special:FilePath/Tarantriss.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (101, 72, 'Polapup', 'Idol on Ice', 'Can be ridden.Can slide quickly down slopes.', 4, 'Frozen', 'Large', 1660, 'Among Polapups, the fastest slider on the snow earns the highest respect.Sometimes, a too-forceful leap sends one tumbling from the sky— a common sight during territorial season.Forecast: clear skies with a chance of flying Polapups.', 'https://palworld.fandom.com/wiki/Special:FilePath/Polapup.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (102, 72, 'Polapup Terra', 'Star of the Dunes', NULL, 4, 'Frozen', 'Large', 1100, 'Among Polapup Terras, the fastest slider on the snow earns the highest respect.Sometimes, a too-forceful leap leaves one buried in the snow— a common sight during particularly competitive seasons.Traffic forecast: heavy Polapup Terra congestion.', 'https://palworld.fandom.com/wiki/Special:FilePath/Polapup Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (103, 73, 'Leezpunk', 'Self-Proclaimed Genius', 'When activated, utilizes its sixth sense to detect nearby dungeons.', 2, 'Dark', 'Small', 2670, 'A Pal that always takes great care to maintain a stylish stance. Always on the hunt for the coolest poses, if given a mirror it will spend all day posing in front of it.', 'https://palworld.fandom.com/wiki/Special:FilePath/Leezpunk.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (104, 73, 'Leezpunk Ignis', 'Self-Proclaimed Fashionista', 'When activated, utilizes its sixth sense to detect nearby dungeons.', 2, 'Scorching', 'Small', 2640, 'A Pal that has an unusual obsession with their standing posture.Always in search of the hottest pose, this Pal''s owner is constantly presented with fervent stances.', 'https://palworld.fandom.com/wiki/Special:FilePath/Leezpunk Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (105, 74, 'Gorirat', 'Jungle Punk', 'When activated,unleashes a primal fury that increases Gorirat''s Attack by 75% for a limited time.', 3, 'Common', 'Large', 2140, 'It beats the ground rhythmically to communicate with its comrades. The meaning of each rhythm differs by troop, but the distinction between them is still largely unknown.', 'https://palworld.fandom.com/wiki/Special:FilePath/Gorirat.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (106, 74, 'Gorirat Terra', 'Up for a Brawl', 'When activated, unleashes a primal fury that increases Gorirat Terra''s attack power.', 3, 'Rocky', 'Large', 1880, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Gorirat Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (107, 75, 'Surfent', 'The Ocean''s Wrath', 'Can be ridden to travel on water.While mounted, prevents stamina depletion while moving over water.', 3, 'Damp', 'Small', 2440, 'Its hydrodynamic form is well suited for activities on water.Poachers often catch them and use them in place of surfboards.', 'https://palworld.fandom.com/wiki/Special:FilePath/Surfent.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (108, 75, 'Surfent Terra', 'The Desert''s Wrath', 'Can be ridden. While in team, Surfent Terra helps carry supplies, decreasing the weight of ores in the player''s inventory.', 3, 'Rocky', 'Large', 1840, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Surfent Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (109, 76, 'Robinquill', 'Archer of the Forest', 'While fighting together, allows you to deal more damage to weak points.', 3, 'Verdant', 'Large', 2260, 'A Pal that is very similar to humans who hunt and live in the forests.It may prove to be a key for understanding what Pals are and how they diverged from humans in the distant past.', 'https://palworld.fandom.com/wiki/Special:FilePath/Robinquill.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (110, 76, 'Robinquill Terra', 'Archer of the Sands', 'While fighting together, allows you to deal more damage to weak points.', 3, 'Verdant', 'Large', 2050, 'A Pal that is very similar to humans who hunt and live in the rocky areas.When Robinquill Terra bones are found in ruins, there are always human bones found nearby as well.', 'https://palworld.fandom.com/wiki/Special:FilePath/Robinquill Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (111, 77, 'Flopie', 'Star of the Flower Beds', 'While in team, appears nearby the player. Automatically picks up nearby items.', 2, 'Verdant', 'Small', 2660, 'It prefers places that have an abundance of vegetation, but hay fever has apparently become a problem for Flopie as of late.', 'https://palworld.fandom.com/wiki/Special:FilePath/Flopie.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (112, 78, 'Wixen', 'Fire-Licked Furball', 'When fighting together, applies Fire damage to the player''s attacks.', 4, 'Scorching', 'Large', 2080, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Wixen.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (113, 78, 'Wixen Noct', 'Phantasmal Furball', 'When fighting together, applies Dark damage to the player''s attacks.', 4, 'Scorching', 'Large', 1490, 'Due to its upbringing, it no longer cares about whether its food is cooked enough. This Pal stopped worrying about those details, and just prefers its food to be as sweet as possible. Not on good terms with Katress Ignis.', 'https://palworld.fandom.com/wiki/Special:FilePath/Wixen Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (114, 79, 'Katress', 'Phantasmal Feline', 'While fighting together, Neutral Pals drop more items when defeated.', 4, 'Dark', 'Large', 2040, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Katress.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (115, 79, 'Katress Ignis', 'Fire-Licked Feline', 'While fighting together, Grass Pals drop more items when defeated.', 4, 'Dark', 'Large', 1800, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Katress Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (116, 80, 'Helzephyr', 'Wings of The Underworld', 'Can be ridden as a flying mount. Applies Dark damage to the player''s attacks while mounted.', 7, 'Dark', 'Large', 1130, 'It calls forth lightning from the depths of hell.Those who dies from Helzephyr''s lightning are sure to have their soul sent to the underworld.', 'https://palworld.fandom.com/wiki/Special:FilePath/Helzephyr.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (117, 80, 'Helzephyr Lux', 'Wings of Netherstorm', 'Can be ridden as a flying mount. Applies Electric damage to the player''s attacks while mounted.', 7, 'Dark', 'Large', 960, 'It calls forth lightning from the depths of hell. While considered a subspecies of Helzephyr, there''s a theory that suggests Helzephyr Lux, struck by lightning from hell, will transform into Helzephyr.', 'https://palworld.fandom.com/wiki/Special:FilePath/Helzephyr Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (118, 81, 'Elgrove', 'Verdant Minotaur', 'When activated, changes the player''s attack type to Grass and increases Attack by 30%.', 8, 'Verdant', 'Large', 2020, 'The leaf on its horn cannot be removed, no matter how hard it is pulled.When the leaf falls on its own, Elgrove accepts its time has come.', 'https://palworld.fandom.com/wiki/Special:FilePath/Elgrove.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (119, 81, 'Elgrove Cryst', 'Frozen Minotaur', 'While in party, grants the player the ability to enemies afflicted with in one strike.', 8, 'Frozen', 'Large', 440, 'Its frozen horn stays solid through its life.When water begins to drip from this ice, Elgrove Cryst feels the chill of its own life slipping away.', 'https://palworld.fandom.com/wiki/Special:FilePath/Elgrove Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (120, 82, 'Lunaris', 'Extraterrestrial', 'While in party, spheres home in on Pals, and carrying capacity is increased by 300. (Does not stack)', 4, 'Common', 'Large', 2010, 'It can control those who carelessly stare into its eyes.Those seen with a Lunaris are in its mind, simply under its control.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lunaris.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (121, 83, 'Fenglope', 'Drifting Cloud', 'Can be ridden. Can double jump while mounted.', 5, 'Common', 'Small', 1960, 'In ages past, its beautiful visage was a common sight in paintings.As time passed, its beautiful pelt and antlers were often seen in works of art.', 'https://palworld.fandom.com/wiki/Special:FilePath/Fenglope.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (122, 83, 'Fenglope Lux', 'Drifting Thundercloud', 'Can be ridden.Can double jump while mounted.While fighting together, Water Pals drop more items when defeated.', 5, 'Electric', 'Small', 900, 'In ages past, it was believed that drawing a picture of Fenglope Lux would result in being struck down by lightning.As time passes, artworks depicting Fenglope Lux became revered as charms to ward off lightning, making them a common presence.', 'https://palworld.fandom.com/wiki/Special:FilePath/Fenglope Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (123, 84, 'Dinossom', 'Guardian of Blossoming Gardens', 'Can be ridden.Enhances Grass attacks while mounted.', 4, 'Verdant', 'Large', 2100, 'A Pal who once angered cannot be pacified.It rages on and on like an inferno.The phrase "step on a Dinossom''s tail" has come to mean enraging someone.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dinossom.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (124, 84, 'Dinossom Lux', 'Guardian of Lightning', 'Can be ridden. Enhances Electric attacks while mounted.', 4, 'Electric', 'Large', 1890, 'Though struck by lightning, it lives on. The phrase "struck by a Dinossom Lux''s bolt" has come to mean narrowly escaping death.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dinossom Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (125, 85, 'Bushi', 'Vagrant Warrior', 'When activated, attacks targeted enemy with a powerful Iaigiri.', 5, 'Scorching', 'Large', 1560, 'Its body becomes a blade upon death, to be taken up by the next generation.If someone other than a Bushi wields this blade, the soul within torments them until they are driven mad.', 'https://palworld.fandom.com/wiki/Special:FilePath/Bushi.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (126, 85, 'Bushi Noct', 'Samurai of Darkness', 'When activated, attacks targeted enemy with a powerful Iagiri.', 5, 'Scorching', 'Large', 840, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Bushi Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (127, 86, 'Munchill', 'Walking Refrigerator', 'While in team, Munchill cools ingredients inside its mouth, making the food in your inventory less likely to spoil.', 3, 'Frozen', 'Small', 2130, 'The inside of its mouth stays pleasantly cold, making it a natural fridge when closed.Its saliva contains enzymes that prevent food from rotting.Thus, it can serve as a food locker for humans— whether it is sanitary or not is another matter entirely.', 'https://palworld.fandom.com/wiki/Special:FilePath/Munchill.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (128, 87, 'Mammorest', 'King of the Forest', 'Can be ridden. Improves efficiency of cutting trees and mining ores while mounted.', 6, 'Verdant', 'Large', 1340, 'The vegetation on its back varies between individuals. There is a long history of appreciating this veritable garden of a Pal, and there are even Mammorest pruning specialists.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mammorest.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (129, 87, 'Mammorest Cryst', 'King of the Tundra', 'Can be ridden. Improves efficiency of cutting trees and mining ores while mounted.', 6, 'Frozen', 'Huge', 1070, 'The vegetation on its back varies between individuals.There was a time when seeds of presumed extinct plants were found still frozen on the back of a Mammorest Cryst.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mammorest Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (130, 88, 'Finsider Ignis', 'Eyes from the Flames', 'While in team, Finsider Ignis helps carry supplies, decreasing the weight of weapons in the player''s inventory.Also increases attack power of Fire Pals.', 2, 'Damp', 'Small', 2240, 'Even if you reach into its mouth, there’s nothing inside—it just keeps going.Thinking it might be an interdimensional space, one researcher tried climbing in like a sleeping bag.But when the gag reflex kicked in, they realized...it’s definitely part of the creature’s body.', 'https://palworld.fandom.com/wiki/Special:FilePath/Finsider Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (131, 88, 'Finsider', 'Eyes from the Abyss', 'While in team, Finsider helps carry supplies, decreasing the weight of weapons in the player''s inventory.', 2, 'Damp', 'Small', 2450, 'It looks like something is peeking out from inside a costume, but even if you reach inside, there’s nothing there.In fact, you can keep reaching deeper and deeper.Perhaps the universe itself lies within.', 'https://palworld.fandom.com/wiki/Special:FilePath/Finsider.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (132, 89, 'Petallia', 'Lady of the Flower Garden', 'When activated, uses medicinal flowers to restore the player''s HP.', 6, 'Verdant', 'Large', 1720, 'A pal that transforms into a massive plant when at the end of its life. Once every ten years, a beautiful flower blooms and a new Petallia is born.', 'https://palworld.fandom.com/wiki/Special:FilePath/Petallia.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (133, 89, 'Petallia Ignis', 'Lady of the Ashen Wastes', 'When activated, soothing blossoms restore the player''s Health by 80%.While in party, player and party Pals take 15% less Grass damage, and are immune to . (Does not stack)', 6, 'Verdant', 'Huge', 820, 'A Pal that burns away into a pile of ash upon the end of its life. The surrounding soil becomes incredibly fertile, allowing an abundance of vegetation to thrive for the following decade.', 'https://palworld.fandom.com/wiki/Special:FilePath/Petallia Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (134, 90, 'Leafan', 'Hardcore Heartbreaker', 'This Pal''s Attack and Defense increase by 2% for each other Grass Pal in your party.', 7, 'Verdant', 'Large', 1410, 'To hone the martial art passed down through a single bloodline: Daily training is the only way! Being distracted by romance? Unthinkable! Daily discipline is the only way! The time has come! Shoot my shot! Instant rejection, that’s all there is! The techniques of love were never passed down... Lingering regret, that’s all there is!', 'https://palworld.fandom.com/wiki/Special:FilePath/Leafan.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (135, 91, 'Incineram Noct', 'Hyena of the Darkest Night', 'When activated, attacks targeted enemy with a powerful Hellfire Claw.', 5, 'Dark', 'Large', 1310, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Incineram Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (136, 91, 'Incineram', 'Hyena of the Wild', 'When activated, attacks targeted enemy with a powerful Hellfire Claw.', 5, 'Scorching', 'Small', 1470, 'In the dark of night, this Pal snatches prey to bring back to its territory.What happens to those poor souls afterwards isn''t too hard to imagine.', 'https://palworld.fandom.com/wiki/Special:FilePath/Incineram.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (137, 92, 'Dazzi', 'Born of the Storm', 'While in team, appears near the player. Follows up player attacks with lightning bolts.', 2, 'Electric', 'Small', 2400, 'Often kind to lonely Pals.However, the moment a Pal mistakes this for actual friendship, it seizes the opportunity to blast them with a thunderbolt.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dazzi.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (138, 92, 'Dazzi Noct', 'Born of the Thunderclouds', 'While in team, appears near the player.Follows up player attacks with dark lightning bolts.', 2, 'Dark', 'Small', 1910, 'Often kind to lonely Pals, it plots to lure them into dropping their guard before striking them down.Yet, Unable to find the right moment, it ends up making friends with them instead.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dazzi Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (139, 93, 'Pyrin', 'Steed of Flames', 'Can be ridden. Applies Fire damage to the player''s attacks while mounted.', 4, 'Scorching', 'Large', 1980, 'Its entire body has evolved into a highly efficient radiator, gifting it with astounding stamina.If someone rides it, this Pal takes caution not to burn them.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pyrin.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (140, 93, 'Pyrin Noct', 'Steed of Darkness', 'Can be ridden. Applies Dark damage to the player''s attacks while mounted.', 4, 'Scorching', 'Large', 1870, 'It burns mysterious dark matter as energy and expels the remaining particles from its body.If someone rides it, they should take care so as not to gallop down the path of darkness.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pyrin Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (141, 94, 'Relaxaurus', 'Gluttonous Dragon', 'Can be ridden. Can rapidly fire a missile launcher while mounted.', 7, 'Dragon', 'Large', 1090, 'Contrary to its blasé appearance, it''s quite ferocious.It perceives everything in its sight as prey and will stop at nothing to devour it.', 'https://palworld.fandom.com/wiki/Special:FilePath/Relaxaurus.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (142, 94, 'Relaxaurus Lux', 'Gluttonous Thunder Dragon', 'Can be ridden. Can rapidly fire a missile launcher while mounted.', 7, 'Dragon', 'Huge', 770, 'One day, Relaxaurus had an idea. Maybe it was about time for a change. Just then, an electric shock raced through its body!', 'https://palworld.fandom.com/wiki/Special:FilePath/Relaxaurus Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (143, 95, 'Foxcicle', 'Frostbound Fox', 'While in a team, increases attack power of Ice pals.', 4, 'Frozen', 'Large', 1970, 'On nights when the aurora is visible, it looks up towards the sky and begins to howl a beautiful song. This does, however, leave it vulnerable to attacks from enemies.', 'https://palworld.fandom.com/wiki/Special:FilePath/Foxcicle.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (144, 96, 'Beakon', 'Wings of Thunderbolt', 'Can be ridden as a flying mount. Applies Electric damage to the player''s attacks while mounted.', 5, 'Electric', 'Large', 1690, 'Some think it is a related species to Ragnahawk, but there is in fact no connection. Using its sharp beak, it descends on its prey in a quick motion that resembles a bolt of lightning.', 'https://palworld.fandom.com/wiki/Special:FilePath/Beakon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (145, 96, 'Beakon Cryst', 'Wings of Frost', NULL, 5, 'Frozen', 'Large', 580, 'Perfectly adapted to colder environments, it hardly feels the cold despite its slender form. Its diving plunge carries tremendous force, as if a giant icicle were dropping straight from the sky.', 'https://palworld.fandom.com/wiki/Special:FilePath/Beakon Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (146, 97, 'Ghangler', 'Temptation in the Deep', 'Can be ridden to travel quickly across water.While fighting together, the time it takes for Pals to bite during night fishing is reduced.', 7, 'Dark', 'Large', 880, 'With its shining lure, it illuminates the darkness.The wandering Pals drawn in by the light stand no chance of escape once spotted by Ghangler.No matter how far, it will keep guiding them until they get home safe and sound.', 'https://palworld.fandom.com/wiki/Special:FilePath/Ghangler.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (147, 97, 'Ghangler Ignis', 'Longing in the Deep', 'Can be ridden to travel quickly across water.While fighting together, the time it takes for Pals to bite during night fishing is reduced.', 7, 'Scorching', 'Large', 720, 'Its blazing lure doubles as a grill for roasting prey.Drawn in by the delicious aroma, Pals have no hope of escape once Ghangler Ignis sets its sights on them.In the end, they’re treated to a hearty meal—until everyone’s full.', 'https://palworld.fandom.com/wiki/Special:FilePath/Ghangler Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (148, 98, 'Rayhound', 'Electro-Charged Zoomies', 'Can be ridden. Can double jump while mounted.', 4, 'Electric', 'Large', 1920, 'At full speed, it could be mistaken for a bolt of lightning.When two Rayhounds collide, a thunderous roar echoes through the air.', 'https://palworld.fandom.com/wiki/Special:FilePath/Rayhound.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (149, 98, 'Rayhound Cryst', 'Frost-Fringed Zoomies', NULL, 4, 'Frozen', 'Large', 1600, 'Sprinting across the tundra at full speed kicks up a blinding blizzard, leading to constant Rayhound Cryst collisions due to zero visibility.', 'https://palworld.fandom.com/wiki/Special:FilePath/Rayhound Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (150, 99, 'Menasting', 'Unstoppable Stinger', 'When fighting together, increases the player''s defense and Electric Pals drop more items when defeated.', 6, 'Dark', 'Huge', 1120, 'Being made of pure energy, its insides are completely hollow. This Pal crams still-living prey into its hollow body, where it absorbs them. Hellish screams of pain can often be heard coming from inside this Pal.', 'https://palworld.fandom.com/wiki/Special:FilePath/Menasting.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (151, 99, 'Menasting Terra', 'Gold-Piercing Spear', 'When fighting together, increases the player''s defense and Electric Pals drop more items when defeated.', 6, 'Rocky', 'Huge', 640, 'Being made of pure energy, its insides are completely hollow.It stuffs earth and minerals into its outer shell, achieving overwhelming mass.Those who are struck by it can only let out hellish groans.', 'https://palworld.fandom.com/wiki/Special:FilePath/Menasting Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (152, 100, 'Needoll', 'Prickly Welcome', 'While in party, increases player''s and Pals'' damage to enemies afflicted with by 50%. (Does not stack)', 2, 'Verdant', 'Small', 2420, 'Its spikes react to its emotions.A dearly cherished Needoll is something one may instinctively want to embrace.But more often than not, it ends in a tragic accident.', 'https://palworld.fandom.com/wiki/Special:FilePath/Needoll.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (153, 100, 'Needoll Noct', 'Binding Spines', 'While in party, the player''s attacks inflict 2. (Does not stack)', 2, 'Dark', 'Small', 1580, 'Its spikes react to its emotions.A well-loved Needoll Noct clings to its owner, but accepting that love means accepting the pain too.', 'https://palworld.fandom.com/wiki/Special:FilePath/Needoll Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (154, 101, 'Reindrix', 'Frosthorn Beast', 'Can be ridden.Keeps the rider cool in hot environments.', 4, 'Frozen', 'Small', 1930, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Reindrix.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (155, 102, 'Mossanda', 'Wanderer of the Forest', 'Can be ridden. Can rapidly fire a grenade launcher while mounted.', 4, 'Verdant', 'Large', 2060, 'A Pal so powerful it''s hard to believe. In one experiment, this Pal tore through 3,000 sheets of paper at once! It''s only by some miracle that this Pal isn''t a meat-eater.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mossanda.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (156, 102, 'Mossanda Lux', 'Inheritor of the Storm', 'Can be ridden. Can rapidly fire a grenade launcher while mounted.', 4, 'Electric', 'Large', 1440, 'A Pal whose power is truly shocking. By altering the electrical currents in its body, this Pal''s been able to overload its own strength. When it comes to sheer power, this Pal may be top of the list.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mossanda Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (157, 103, 'Chillet', 'Dancer on the Steppe', 'Can be ridden.Applies Dragon damage to the player''s attacks while mounted.', 3, 'Frozen', 'Small', 2330, 'It can curl up its body and roll around at extremely high speeds.Long ago, people would tie bags of milk to domesticated Chillet as they grazed to produce butter using this spinning force.', 'https://palworld.fandom.com/wiki/Special:FilePath/Chillet.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (158, 103, 'Chillet Ignis', 'Cherry Blossom Dancer', 'Can be ridden.Applies Fire damage to the player''s attacks while mounted.', 3, 'Scorching', 'Large', 1950, 'It can curl up its body and roll around so fast that sparks fly.Sparks also fly when it feels excited.If you stroke it too much, this pal will get fired up, literally!', 'https://palworld.fandom.com/wiki/Special:FilePath/Chillet Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (159, 104, 'Ragnahawk', 'Wings of Inferno', 'Can be ridden as a flying mount. Applies Fire damage to the player''s attacks while mounted.', 7, 'Scorching', 'Large', 1050, 'Some think it is a related species to Beakon, but there is in fact no connection. It mainly eats rocks, and after many long years its beak and head have hardened to accommodate this diet.', 'https://palworld.fandom.com/wiki/Special:FilePath/Ragnahawk.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (160, 105, 'Moldron', 'Scorched Wanderer', NULL, 8, 'Scorching', 'Large', 750, 'In a healthy individual, the lava on its back flows smoothly.However, a poor lifestyle will gradually worsen its circulation, eventually causing a lava clog that results in a sudden, massive explosion.', 'https://palworld.fandom.com/wiki/Special:FilePath/Moldron.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (161, 105, 'Moldron Cryst', 'Frigid Voyager', NULL, 8, 'Frozen', 'Large', 380, 'In a healthy individual, the substance flowing along its back maintains a stable temperature.However, if its heartbeat quickens, the temperature destabilizes, eventually triggering vaporization or crystallization that results in a sudden, abrupt death from shock.', 'https://palworld.fandom.com/wiki/Special:FilePath/Moldron Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (162, 106, 'Palumba', 'No Dance, No Life', 'Can be ridden.Runs faster over grass.', 6, 'Verdant', 'Large', 1240, 'Disrupts enemies’ rhythm with a signature dance.In turf battles, the first to fall in sync with the other’s rhythm loses.Courtship, boredom, battle—it all comes down to dance!Now then, what could a dance aimed at a human possibly mean?', 'https://palworld.fandom.com/wiki/Special:FilePath/Palumba.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (163, 107, 'Digtoise', 'Drilling Machine', 'When activated, performs Shell Spin, follows the player while spinning, and mines ores efficiently.', 5, 'Rocky', 'Large', 1550, 'A Digtoise possessing the strongest shell and the only drill capable of piercing it, ponders the contradictions of the world in the popular children''s tale, "Digtoise''s Fable".', 'https://palworld.fandom.com/wiki/Special:FilePath/Digtoise.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (164, 108, 'Broncherry', 'Winds of Spring', 'Can be ridden. While in team, Broncherry helps carry supplies, increasing the player''s max carrying capacity.', 6, 'Verdant', 'Large', 1380, 'Its scent drastically changes before and after pairing. It exudes a pleasing aroma after finding a partner, which is called the "fragrance of first love."', 'https://palworld.fandom.com/wiki/Special:FilePath/Broncherry.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (165, 108, 'Broncherry Aqua', 'Waves of Summer', 'Can be ridden. While in team, Broncherry helps carry supplies, increasing the player''s max carrying capacity.', 6, 'Verdant', 'Large', 1080, 'Its scent drastically changes before and after pairing. It exudes a pleasing aroma before finding a partner, which is called the "perfume of purity."', 'https://palworld.fandom.com/wiki/Special:FilePath/Broncherry Aqua.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (166, 109, 'Dumud', 'Perpetual Procrastinator', 'While in team, increases attack power of Ground Pals.', 3, 'Rocky', 'Small', 2290, 'When too relaxed, its reaction time drastically declines.Even if it were sliced from head to tail, it probably wouldn''t even realize that it should be dead until the next morning.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dumud.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (167, 109, 'Dumud Gild', 'Piece of Cake', 'While in team, increases attack power of Ground Pals.Sometimes, drop High Quality Pal Oil when assigned to Ranch with a small chance to drop Gold Coin.', 3, 'Rocky', 'Large', 1620, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Dumud Gild.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (168, 110, 'Braloha', 'Ancient Bloombringer', 'Can be ridden.While at base, shortens the time it takes Pals assigned to to produce eggs.(This effect does not stack.)', 7, 'Verdant', 'Large', 1030, 'Its breath carries a miraculous, pollen-like substance that pollinates any plant it touches.For plant-based Pals, being near it can be a bit… complicated.', 'https://palworld.fandom.com/wiki/Special:FilePath/Braloha.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (169, 111, 'Kitsun', 'Guardian of the Azure Flame', 'Can be ridden. Unaffected by the cold or heat while riding this Pal.', 5, 'Scorching', 'Large', 1670, 'Despite its appearance, Kitsun is extremely sensitive and will flee into a cave when spooked.Long ago, it was considered an ill omen if one ran away from you.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kitsun.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (170, 111, 'Kitsun Noct', 'Guardian of the Dark Flame', 'Can be ridden.Applies Dark damage to the player''s attacks while mounted.', 5, 'Dark', 'Large', 800, 'Despite its appearance, Kitsun Noct is extremely sensitive and will flee into a cave when spooked.It has become quite gloomy from being a shut-in for too long.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kitsun Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (171, 112, 'Blazehowl', 'Crimson Goliath', 'Can be ridden. While fighting together, Grass Pals drop more items when defeated.', 6, 'Scorching', 'Large', 1360, 'While it prefers raw meat, it always ends up eating well-done meat. This is due to its blistering claws, which it uses as its weapon—it simply doesn''t realize its prey gets burned to a crisp.', 'https://palworld.fandom.com/wiki/Special:FilePath/Blazehowl.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (172, 112, 'Blazehowl Noct', 'Inferno Goliath', 'Can be ridden.While fighting together, Neutral Pals drop more items when defeated.', 6, 'Scorching', 'Large', 1270, 'While it prefers raw meat, it always ends up eating tainted meat.This is due to its dark claws, which it uses as its weapon—it simply doesn''t realize its prey gets cursed.', 'https://palworld.fandom.com/wiki/Special:FilePath/Blazehowl Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (173, 113, 'Warsect', 'Unyielding Colossus', 'When fighting together, increases player''s defense and applies Fire damage to the player''s attacks.', 6, 'Rocky', 'Large', 1280, 'The ultra-hard armor surrounding its body is extremely strong and heat resistant. Even a napalm blast would hardly leave a scratch.', 'https://palworld.fandom.com/wiki/Special:FilePath/Warsect.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (174, 113, 'Warsect Terra', 'Gold-Armored Warrior', 'When fighting together, increases the player''s defense and reduces damage received from Fire.', 6, 'Rocky', 'Huge', 630, 'The ultra-hard armor surrounding its body is extremely strong and heat resistant. It doesn''t flinch even if a Mammorest steps on it.', 'https://palworld.fandom.com/wiki/Special:FilePath/Warsect Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (175, 114, 'Frostplume', 'Snowlaced Feather Mantle', 'While fighting together, Frostplume''s icy aura sharpens your focus, improving reload speed.', 5, 'Frozen', 'Small', 860, 'So precise is its sense of time that it awakens at the exact same hour every morning.According to Palpagos lore, a day was divided into 24 parts because when Frostplume spreads its tail feathers wide, it reveals a pattern with 24 distinct spaces.', 'https://palworld.fandom.com/wiki/Special:FilePath/Frostplume.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (176, 115, 'Majex', 'Flickering Shadow', 'While in party, when the player attacks an enemy afflicted with , the enemy creates flames around itself, dealing continuous damage equal to 15% of the player''s attack damage to enemies that come into contact with them. (Does not stack.)', 8, 'Dark', 'Large', 1010, 'It appears to be striking a heroic pose, but the reality is that it''s simply bracing itself against the weight of its tail and hair to avoid toppling over.', 'https://palworld.fandom.com/wiki/Special:FilePath/Majex.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (177, 116, 'Sibelyx', 'Pallid Lady', 'When activated, attacks targeted enemy with a powerful Blizzard Spike. Sometimes produces High Quality Cloth when assigned to Ranch.', 5, 'Frozen', 'Large', 1810, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Sibelyx.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (178, 116, 'Sibelyx Primo', 'Gilded Lady', 'While in party, increases Defense of Neutral Pals by 15%. (Does not stack)Sometimes makes High Quality Cloth when assigned to .', 5, 'Common', 'Large', 650, 'A Pal that loves gazing into the void, and will often remain completely still.It frequently becomes a gathering spot for smaller Pals.', 'https://palworld.fandom.com/wiki/Special:FilePath/Sibelyx Primo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (179, 117, 'Maraith', 'Messenger of Death', 'Can be ridden.Applies Dark damage to the player''s attacks while mounted.', 5, 'Dark', 'Large', 1710, 'It relishes the peculiar scent living things give off when they are near death.If a Maraith has taken a liking to you, it is safe to assume that is why.', 'https://palworld.fandom.com/wiki/Special:FilePath/Maraith.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (180, 118, 'Shroomer', 'Creeping Mushroom', 'Can be ridden.While at a base, its mysterious spores slow the rate at which the SAN value of allies at the base decreases.', 5, 'Verdant', 'Small', 1520, 'Inhaling large amounts of its spores will put you into a trance. Sometimes, if Shroomer appears motionless, it''s not because it''s mimicking a mushroom, but rather because it''s high off its own spores.', 'https://palworld.fandom.com/wiki/Special:FilePath/Shroomer.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (181, 118, 'Shroomer Noct', 'Dangerous Mushroom', 'Can be ridden.While at a base, its mysterious spores slow the rate at which the SAN value of allies at the base decreases.', 5, 'Verdant', 'Large', 1450, 'The abundance of spores released by this Pal blocks out sunlight. Sometimes, if Shroomer Noct appears motionless, it''s not because it''s mimicking a mushroom, but rather because its own spores don''t let it see anything.', 'https://palworld.fandom.com/wiki/Special:FilePath/Shroomer Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (182, 119, 'Icelyn', 'Icy Smile', 'While fighting together, changes the player''s attack type to Ice. and increases Attack by 30%.', 5, 'Frozen', 'Small', 1260, 'Though its body melts in the heat, it just can''t resist sunbathing.Though its body melts in the warmth, it likes hot springs too much.If it''s going to melt anyway, it hopes it''ll be in a steaming outdoor bath under a clear blue sky.', 'https://palworld.fandom.com/wiki/Special:FilePath/Icelyn.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (183, 120, 'Gildra', 'Golden Blade of Duat', 'While fighting together, when is incapacitated, it revives with its Hunger reduced to 0.', 6, 'Dark', 'Large', 1170, 'The golden, bandage-like organs covering its body are highly elastic.However, they are prone to tearing under extremely dry conditions, so daily moisture checks are absolutely essential.', 'https://palworld.fandom.com/wiki/Special:FilePath/Gildra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (184, 121, 'Jormuntide', 'Emperor of the Sea', 'Can be ridden to travel on water. While mounted, prevents stamina depletion while moving over water.', 8, 'Dragon', 'Large', 590, 'Legend says the Jormuntide was once a wise man who, after being wrongly convicted and cast into a whirlpool, returned as this Pal to annihilate the kingdom.', 'https://palworld.fandom.com/wiki/Special:FilePath/Jormuntide.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (185, 121, 'Jormuntide Ignis', 'Volcanic Emperor', 'Can be ridden. Enhances Fire attacks while mounted.', 8, 'Dragon', 'Huge', 170, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Jormuntide Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (186, 122, 'Suzaku', 'Ruler of the Crimson Dawn', 'Can be ridden as a flying mount. Enhances Fire attacks while mounted.', 7, 'Scorching', 'Large', 1200, 'It was once believed to usher in the dry season.Whenever there was a drought the previous year, people would relentlessly seek to cull its numbers, hoping to bring about a plentiful harvest in the next year.', 'https://palworld.fandom.com/wiki/Special:FilePath/Suzaku.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (187, 122, 'Suzaku Aqua', 'Ruler of the Cobalt Dusk', 'Can be ridden as a flying mount. Enhances Water attacks while mounted.', 7, 'Damp', 'Huge', 740, 'It was once believed to usher in the rainy season.Whenever there was a flood the previous year, people would relentlessly seek to cull its numbers, hoping to avert disaster in the coming year.', 'https://palworld.fandom.com/wiki/Special:FilePath/Suzaku Aqua.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (188, 123, 'Dazemu', 'Brilliant Steps', 'Can be ridden.Runs faster over sand.', 3, 'Rocky', 'Large', 2210, 'Take one step forward and forget your doubts. Take two steps forward and forget your worries. Take three steps forward and forget your fears. Face any enemy.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dazemu.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (189, 124, 'Quivern', 'Snow-White Soarer', 'Can be ridden as a flying mount. Enhances Dragon attacks while mounted.', 6, 'Dragon', 'Large', 1210, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Quivern.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (190, 124, 'Quivern Botan', 'Evergreen Flyer', 'Can be ridden as a flying mount.Enhances Grass attacks while mounted.', 6, 'Dragon', 'Large', 1300, 'When you hug Quivern Botan, if it smells like sunshine and meadows, tomorrow will be sunny. If it smells damp, tomorrow will be wet and miserable.', 'https://palworld.fandom.com/wiki/Special:FilePath/Quivern Botan.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (191, 125, 'Lullu', 'Primal Source of Hay Fever', 'While at a base, Lullu fills the farm with good spirits, increasing the growth rate of the crops.', 4, 'Verdant', 'Small', 1990, 'In early spring, pollen floats on the wind throughout the island. Flopie''s hay fever is Lullu''s fault.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lullu.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (192, 126, 'Kikit', 'Armored to the Teeth', 'While in team, Kikit helps carry supplies, decreasing the weight of crude oil in the player''s inventory.', 3, 'Rocky', 'Small', 2310, 'A decade ago, Kikit soccer was popular.However, it quickly fell out of favor due to fierce opposition from the Free Pal Alliance.Nevertheless, the Kikit''s themselves didn''t mind because it helped shed their old carapace.', 'https://palworld.fandom.com/wiki/Special:FilePath/Kikit.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (193, 127, 'Yakumo', 'Unwavering Loyalty', 'Can be ridden. While fighting together, 15% increased chance of encountering pals with the same Passive Skill as this Pal. (Excludes certain Passive Skills)', 3, 'Common', 'Small', 2230, 'It has a strong sense of justice and despises evil. In the past they were faithful and loving companions to the islanders. Nowadays, Yakumos are hostile to humans wherever they spot them.', 'https://palworld.fandom.com/wiki/Special:FilePath/Yakumo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (194, 128, 'Skutlass Ignis', 'Blazing Determined Draw', NULL, 5, 'Damp', 'Large', 1590, 'A bizarre species which temporarily separates its body and uses its bones to slice through enemies, at the risk of perishing itself upon taking too long. While unconfirmed, older individuals are said to deliberately stay separated in order to trigger their survival instincts and prolong their lifespans.', 'https://palworld.fandom.com/wiki/Special:FilePath/Skutlass Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (195, 129, 'Reptyro', 'Lava-Devouring Juggernaut', 'Can be ridden. Improves efficiency of mining ores while mounted.', 7, 'Scorching', 'Large', 1060, 'Magma-like blood runs throughout its body.If a large amount of water is thrown on it, the water rapidly heats, causing an immense vapor explosion.', 'https://palworld.fandom.com/wiki/Special:FilePath/Reptyro.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (196, 129, 'Reptyro Cryst', 'Ice-Breaking Juggernaut', 'Can be ridden. Improves efficiency of mining ores while mounted.', 7, 'Frozen', 'Large', 600, 'Ice cold blood runs throughout its body. If heated rapidly, its blood evaporates, causing an immense vapor explosion.', 'https://palworld.fandom.com/wiki/Special:FilePath/Reptyro Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (197, 130, 'Starryon', 'Midnight Blue Mane', 'Can be ridden.Increases movement speed while mounted at night.', 6, 'Dark', 'Large', 1150, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Starryon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (198, 130, 'Starryon Primo', 'Silvermane', NULL, 6, 'Common', 'Large', 430, 'It takes great pride in its glowing, gorgeous mane.If it gets even slightly dirty, it becomes so mortified it can''t focus on running properly.Because skin oils ruin its coat, it wants to avoid being touched too much, even by its favorite Pal Tamer.', 'https://palworld.fandom.com/wiki/Special:FilePath/Starryon Primo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (199, 131, 'Pierdon', 'Shambling Vein', NULL, 8, 'Rocky', 'Large', 1110, 'It smashes its body against harder rocks to maintain its preferred shape.Those with noticeable dents are best left alone, much like people with a botched haircut.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pierdon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (200, 131, 'Pierdon Cryst', 'Shuffling Glacier', NULL, 8, 'Frozen', 'Large', 460, 'It basks in the sun, rotating just enough to melt its ice into its preferred shape.Lopsided ones should be left alone, much like a person who was a little too bold with their sideburns.', 'https://palworld.fandom.com/wiki/Special:FilePath/Pierdon Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (201, 132, 'Cryolinx', 'Predator of Snowy Peaks', 'While fighting together, Dragon Pals drop 40% more items when defeated. (Does not stack)', 7, 'Frozen', 'Large', 1040, 'It can easily climb steep mountains with its hard claws. However, its short legs make it difficult to descend, often leaving it stranded in high places.', 'https://palworld.fandom.com/wiki/Special:FilePath/Cryolinx.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (202, 132, 'Cryolinx Terra', 'Predator of the Earth', 'While fighting together, Electric Pals drop more items when defeated.', 7, 'Rocky', 'Large', 470, 'It can easily carry many items with its large hands.However, its short legs slow its pace, often leaving it overtaken by nightfall.', 'https://palworld.fandom.com/wiki/Special:FilePath/Cryolinx Terra.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (203, 133, 'Snugloo', 'Alpine Dwarf', NULL, 5, 'Frozen', 'Small', 2390, '“To look at a Snugloo''s eyes” is an expression which means to seek the unseen essence of things.Ironically, no researcher has ever confirmed whether Snugloos have eyes in the first place.', 'https://palworld.fandom.com/wiki/Special:FilePath/Snugloo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (204, 134, 'Wumpo', 'Guardian of the Snowy Fields', 'Can be ridden. While in team, Wumpo helps carry supplies, increasing the player''s max carrying capacity.', 7, 'Frozen', 'Large', 830, 'Researchers once tried to shave off its hair to reveal its true form. In the end, only hair was left, as if that was all there was to begin with.', 'https://palworld.fandom.com/wiki/Special:FilePath/Wumpo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (205, 134, 'Wumpo Botan', 'Guardian of the Grassy Fields', 'Can be ridden. While in team, Wumpo Botan helps carry supplies, increasing the player''s max carrying capacity.', 7, 'Verdant', 'Large', 610, 'Researchers once tried to cut the grass off its body to reveal its true form. In the end, only grass was left, as if that was all there was to begin with.', 'https://palworld.fandom.com/wiki/Special:FilePath/Wumpo Botan.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (206, 135, 'Sootseer', 'Flickering Flame', 'Sometimes digs up Bone when assigned to Ranch.', 7, 'Dark', 'Large', 980, 'It was once believed that as the world approached its end, the flame would weaken. Doomsayers would repeatedly rejoice when the flame began to weaken, but in the end, it turned out to be a prank by Sootseer. At least, for now.', 'https://palworld.fandom.com/wiki/Special:FilePath/Sootseer.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (207, 136, 'Carnibora', 'Open-Minded Glutton', NULL, 7, 'Verdant', 'Large', 1700, 'Prone to eating indiscriminately, the mouth atop its head frequently breaks out in agonizing ulcers, causing it to use the mouth on its face instead.However, its behavior doesn''t change, which leads to both mouths suffering the same ulcers.', 'https://palworld.fandom.com/wiki/Special:FilePath/Carnibora.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (208, 137, 'Blazamut', 'Cursed Tyrant', 'Can be ridden. While in party, increases the Attack and Defense of the Pal fighting alongside you by 5% whenever you defeat an enemy. This effect lasts 20 seconds and stacks up to 5 times.', 9, 'Scorching', 'Huge', 410, 'Legends say it was born during a volcanic eruption. A strange group even claims that this continent is laid upon the back of a giant Blazamut.', 'https://palworld.fandom.com/wiki/Special:FilePath/Blazamut.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (209, 137, 'Blazamut Ryu', 'Incarnation of the Eternal Flame', 'Can be ridden.Enhances Dragon attacks while mounted.', 9, 'Dragon', 'Huge', 100, 'Long ago, it emerged from the depths of the earth.With relentless, raging flames showing no mercy, it burned the entire island until nothing remained.It was known as the Eternal Flame.', 'https://palworld.fandom.com/wiki/Special:FilePath/Blazamut Ryu.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (210, 138, 'Dualith', 'Twinhearted Azure Construct', NULL, 8, 'Rocky', 'Large', 510, 'One entity, two minds.When their wills clash, it''s impossible to tell where the armor will wander until they reconcile.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dualith.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (211, 138, 'Dualith Noct', 'Twinhearted Violet Construct', NULL, 8, 'Rocky', 'Large', 250, 'One entity, two minds.They rarely agree and bicker constantly, but once battle begins, mind and body instantly unite as one!', 'https://palworld.fandom.com/wiki/Special:FilePath/Dualith Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (212, 139, 'Anubis', 'Guardian of the Dark Sun', 'When fighting together, applies Ground damage to the player''s attacks. Sometimes dodges attacks with a high speed sidestep while in a battle.', 8, 'Rocky', 'Huge', 480, 'Once seen as a symbol of nobility, and an idol for those who shunned wealth and power.Yet over time, this Pal became a token of death.', 'https://palworld.fandom.com/wiki/Special:FilePath/Anubis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (213, 140, 'Sekhmet', 'Cutthroat Sun Snuffer', NULL, 7, 'Rocky', 'Large', 870, 'Once a fierce creature feared as a symbol of death.When Anubis claimed that mantle, wealthy elites looking for a replacement beguiled the species with wine.Before long, Sekhmet became a symbol of high nobility.', 'https://palworld.fandom.com/wiki/Special:FilePath/Sekhmet.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (214, 141, 'Prixter', 'Bad Boy', 'When activated, it can analyze airborne particles and find a dungeon''s exit.', 5, 'Dark', 'Large', 1510, 'It has about 5,000 types of venom.Some of them are deadly enough to cause instant death, but none are present in a high enough concentration to have any effect.', 'https://palworld.fandom.com/wiki/Special:FilePath/Prixter.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (215, 141, 'Prixter Lux', 'Thunderboy', NULL, 5, 'Electric', 'Large', 850, 'It pierces foes with its tail to deliver an electric jolt directly into their bodies.However, the current it generates is extremely weak, so a simple punch would do far more damage.', 'https://palworld.fandom.com/wiki/Special:FilePath/Prixter Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (216, 142, 'Tetroise Primo', 'Sandsea Wardenstone', NULL, 8, 'Common', 'Large', 200, 'Even if the stones on its back were to be removed, Tetroise Primo will know where they are.No matter how far apart, it will always track them down.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tetroise Primo.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (217, 142, 'Tetroise', 'Sandsea Monolith', 'Can be riddenWhile at a base, increases the Work Suitability Level for all other Base Pals by +1. (Does not stack)', 8, 'Rocky', 'Large', 790, 'Those stones on its back are not just cargo.Set them down somewhere distant and they will slowly make their way back home.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tetroise.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (218, 143, 'Nyafia', 'Night Shade Hunter', 'When activated,Nyafia will fire a shotgun at nearby enemies for a limited time.', 6, 'Dark', 'Small', 1250, 'Strongly dislikes anyone catching a glimpse of its concealed eye.If you insist on trying, it''ll burst into tears and ignore you for two weeks.', 'https://palworld.fandom.com/wiki/Special:FilePath/Nyafia.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (219, 144, 'Mimog', 'Treasure Trove', 'When near a treasure chest, Mimog can open the chest without using a key.The type of treasure chest that can be opened depends on the skill level.', 3, 'Common', 'Large', 1740, 'There was once a tradition of handing out an award to the person who met their end in the most foolish way.The first award was given for "being unaware of Mimog, opening the chest, and being bitten to death."', 'https://palworld.fandom.com/wiki/Special:FilePath/Mimog.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (220, 145, 'Xenovader', 'Interloper from Outer Space', 'While in party, increases the damage of the last bullet fired from a full-auto weapon by 100%. (Does not stack)', 4, 'Dark', 'Large', 1820, 'Can send information and convert it into energy by forgetting it. Regularly seems to be sending information to someone. - Respond. Target located. Proceed to immediate destruction.', 'https://palworld.fandom.com/wiki/Special:FilePath/Xenovader.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (221, 146, 'Xenogard', 'Planet-Devouring Dragon', 'Can be ridden.While in the team, it''s easier to obtain Meteorite Fragment and Pure Quartz.', 7, 'Dragon', 'Huge', 990, 'Consumes information and turns it into energy.Regularly seems to be sending information to someone.- Hello? What was the message you just sent? I devoured it before checking.', 'https://palworld.fandom.com/wiki/Special:FilePath/Xenogard.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (222, 147, 'Prunelia', 'Indigo Handmaiden', 'While at a base,Prunelia''s prayers bless the crops, increasing their harvest.', 5, 'Verdant', 'Large', 1390, 'Intelligent and graceful in its demeanor, it was frequently employed as an attendant by the island''s nobles.However, when encountered at night, its face looked so eerie that it quickly fell out of favor.', 'https://palworld.fandom.com/wiki/Special:FilePath/Prunelia.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (223, 148, 'Nitemary', 'Soul of the Dark Rabbit', 'While fighting together, Pals drop more Pal Souls when defeated.', 6, 'Dark', 'Large', 1230, 'What it carries is its own soul.When it falls for someone, it forcibly extracts their soul and merges it with its own, yearning to become one.', 'https://palworld.fandom.com/wiki/Special:FilePath/Nitemary.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (224, 148, 'Nitemary Botan', 'Soul of the Green Rabbit', NULL, 6, 'Verdant', 'Large', 1320, 'What it carries is its own soul.When it falls for someone, it flings its soul at them to merge it with theirs, yearning to become one.', 'https://palworld.fandom.com/wiki/Special:FilePath/Nitemary Botan.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (225, 149, 'Smokie', 'Jet-Black Little Hero', 'When activated, uses its sharp sense of smell to detect nearby Chromite.While fighting together, a large amount of Chromite is obtained.', 3, 'Dark', 'Small', 1760, 'The black flames are merely warm to the touch, but anything left in contact with them slowly melts from the inside.Hold some cheese over them, and it becomes a true delicacy.', 'https://palworld.fandom.com/wiki/Special:FilePath/Smokie.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (226, 149, 'Smokie Cryst', 'Chilly Little Hero', NULL, 3, 'Dark', 'Small', 1610, 'The blue flames are merely cool to the touch, but anything left in contact with them slowly freezes.Hold a milk bottle over them, and you get a frozen milkshake!', 'https://palworld.fandom.com/wiki/Special:FilePath/Smokie Cryst.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (227, 150, 'Omascul', 'Hundred-Faced Apostle', 'While in team, the Pals in the team gain more experience points.', 5, 'Dark', 'Small', 1140, 'The mask it wears is not its face, they say.It seems in front, but it''s not there, no way.From shadows deep, it watches night and day.Glance away, and closer it will stray.', 'https://palworld.fandom.com/wiki/Special:FilePath/Omascul.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (228, 151, 'Whalaska', 'Gentle Ice Lance', 'Can be ridden.While fighting together, fishing minigames begin with the capture gauge more filled than usual.Additionally, the capture gauge increases more rapidly while the bars are overlapping.', 8, 'Frozen', 'Large', 710, 'When it sleeps, Pals often mistake it for a drifting piece of ice and rest on it.Although gentle and unwilling to push them away when awake, it feels quietly stressed by the intrusion on its personal space.', 'https://palworld.fandom.com/wiki/Special:FilePath/Whalaska.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (229, 151, 'Whalaska Ignis', 'Gentle Crimson Lance', 'Can be ridden.While fighting together, fishining minigames begin with the capture gauge more filled than usual.Additionally, the capture gauge increases more rapidly while the bars are overlapping.', 8, 'Frozen', 'Large', 370, 'Determined never to be mistaken for drift ice again, it turned bright red through sheer will.Unfortunately, some Pals can’t see red.So despite its efforts, its personal space continues to be invaded.', 'https://palworld.fandom.com/wiki/Special:FilePath/Whalaska Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (230, 152, 'Verdash', 'Gale of the Forest', 'While in party, grants 1 additional jump and 1 additional mid-air dash. (Does not stack)', 6, 'Verdant', 'Large', 1160, 'Land that Verdash has run across becomes extremely fertile, with thick vegetation growing soon after.It will not run anywhere that herbicide has been used.', 'https://palworld.fandom.com/wiki/Special:FilePath/Verdash.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (231, 153, 'Splatterina', 'Crimson Butcher', 'While in possession, the amount of items obtained from using the increases.', 7, 'Dark', 'Small', 780, 'It has an uncontrollable urge to tear its prey apart.Each individual has their own meticulous order for dismemberment.If caught by Splatterina, pray that your head is taken first.', 'https://palworld.fandom.com/wiki/Special:FilePath/Splatterina.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (232, 154, 'Gildane', 'Guardian Beast of Twilight', 'Can be ridden.Applies Ground damage to player''s attack while mounted.', 8, 'Rocky', 'Large', 730, 'During the golden age of alchemy on the island, its ever-glowing golden fur was highly prized as a catalyst for transmuting gold.In time, a remarkable revelation was made:the same golden hue could be achieved simply by processing its mane.', 'https://palworld.fandom.com/wiki/Special:FilePath/Gildane.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (233, 155, 'Dogen', 'State of Enlightenment', 'When activated, moves to the closest base.Cannot be used within dungeons, etc.', 5, 'Common', 'Large', 1460, 'Striving for a state of selflessness, it meditates endlessly.After confronting its worldly desires, it eats a meal and reflects.It ate too much today.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dogen.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (234, 156, 'Bulldosu', 'Bangin'' Yokozuna', NULL, 6, 'Rocky', 'Small', 1190, 'In the old islands, Bulldosu sumo was widely enjoyed.At the highest levels, even a charging Rushoar would be sent flying instead.', 'https://palworld.fandom.com/wiki/Special:FilePath/Bulldosu.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (235, 157, 'Celesdir', 'Beast of Salvation', 'Can be ridden.Increases the player''s auto recovery speed while mounted.', 8, 'Common', 'Large', 570, 'Ancient texts refer to it as the "Beast of Salvation."The light emitted by Celesdir purifies everything, literally causing things to vanish from existence without leaving a trace.', 'https://palworld.fandom.com/wiki/Special:FilePath/Celesdir.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (236, 157, 'Celesdir Noct', 'Beast of Chaos', NULL, 8, 'Dark', 'Large', 270, 'Where blinding radiance shines, dark shadows are born.It scatters an all-enveloping darkness to reclaim the chaos that ought to be.Balance is what the world requires.', 'https://palworld.fandom.com/wiki/Special:FilePath/Celesdir Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (237, 158, 'Astegon', 'Draconic Monarch of Steel', 'Can be ridden a flying mount.Increases the damage dealt to ores by 1,100%, and you can obtain 150% more Ore while mounted.', 7, 'Dragon', 'Huge', 490, 'A savage beast born of the abyss. Thou shall not stand before the beast. Thou shall not heed the beast.', 'https://palworld.fandom.com/wiki/Special:FilePath/Astegon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (238, 159, 'Knocklem', 'Suit of Armor', 'When activated, a steel resolve increases Knocklem''s attack and defense.', 9, 'Rocky', 'Huge', 260, 'Can be disassembled into 215 parts.It is capable of being reassembled and functioning again even if the parts are scattered.Mixing parts from different individuals will trigger a malfunction due to mistaken identity.', 'https://palworld.fandom.com/wiki/Special:FilePath/Knocklem.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (239, 159, 'Knocklem Ignis', 'Blazing Suit of Armor', NULL, 9, 'Scorching', 'Huge', 210, 'Upon disassembly, it is capable of being reassembled and functioning again.Mixing parts from different individuals will trigger a fatal cognitive error that causes its systems to overheat.', 'https://palworld.fandom.com/wiki/Special:FilePath/Knocklem Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (240, 160, 'Silvegis', 'Guardian Dragon of Ironclad', 'Can be ridden.Increases the duration of the shield when using Aegis Charge while mounted.', 8, 'Dragon', 'Large', 560, 'The metallic components around its neck possess magnetic properties.If the leg pieces get too close, they cling to it.When metal debris builds up on its neck, it grudgingly begins cleaning, and grows frustrated when they won''t come off easily.', 'https://palworld.fandom.com/wiki/Special:FilePath/Silvegis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (241, 161, 'Azurmane', 'Blue Lightning Steed', 'Can be ridden.Also allows dashing in the air and moving at high speed.', 8, 'Electric', 'Large', 420, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Azurmane.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (242, 162, 'Valentail', 'Plays Both Sides', NULL, 4, 'Common', 'Small', 1900, 'In older paintings, it is depicted as much smaller than it is today.For reasons unknown, various parts of its body have begun to elongate rapidly in recent years, and it is predicted to reach nearly ten times its current size within the next century.', 'https://palworld.fandom.com/wiki/Special:FilePath/Valentail.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (243, 163, 'Snock', 'Sluggish Blue Bolt', NULL, 4, 'Electric', 'Small', 1780, 'Tossing an Snock into the bath for a shock spa is considered a traditional health practice.That is to say, the results may be rather shocking.', 'https://palworld.fandom.com/wiki/Special:FilePath/Snock.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (244, 163, 'Snock Lux', 'Sluggish Dazzling Flash', NULL, 4, 'Electric', 'Small', 1500, 'Tossing a heated Snock Lux into the bath for a scorching spa was once a fad of the distant past.Owing to a recent revival, it is now quite literally a hot trend.', 'https://palworld.fandom.com/wiki/Special:FilePath/Snock Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (245, 164, 'Souffline', 'Windborne Seedling', NULL, 3, 'Verdant', 'Small', 2000, 'Its fluff can be used to hide away unpleasant memories.Once carried off by the wind, you can bid farewell to the darkness they carried.', 'https://palworld.fandom.com/wiki/Special:FilePath/Souffline.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (246, 165, 'Lapiron', 'Indomitable Racer', NULL, 4, 'Rocky', 'Small', 1680, 'Listens to the earth as it runs, avoiding unstable footing with ease.However, uncooperative terrain will trick it into falling over constantly.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lapiron.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (247, 166, 'Hoodle', 'Vanishing Master', NULL, 3, 'Dark', 'Small', 1770, 'When it sleeps, it deflates.When it sleeps, it''s no longer there.A sleeping Hoodle cannot exist; Therefore, Hoodle never sleeps.', 'https://palworld.fandom.com/wiki/Special:FilePath/Hoodle.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (248, 167, 'Slowatt', 'Shockingly Laid-Back', NULL, 4, 'Electric', 'Small', 1750, 'Doing as they please, sleeping when they wish, and eating whatever they like.Surely, Slowatt must be toiling in secret to maintain such a luxury....Or so the old islanders told themselves, just to get by.', 'https://palworld.fandom.com/wiki/Special:FilePath/Slowatt.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (249, 168, 'Bakemi', 'Freakily Cute', NULL, 5, 'Dark', 'Small', 1540, 'It lives entirely for the thrill of the scare, but is utterly un-frightening.As most cannot help but indulge it with feigned surprise for its cuteness, Bakemi now leaves a trail of smiles in its wake.', 'https://palworld.fandom.com/wiki/Special:FilePath/Bakemi.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (250, 169, 'Solmora', 'Buoyant Baron', NULL, 6, 'Damp', 'Small', 1370, 'Its corkscrew tail acts as a propeller.Research claims that if its body could withstand the strain, it could reach speeds beyond 88 mph.', 'https://palworld.fandom.com/wiki/Special:FilePath/Solmora.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (251, 169, 'Solmora Lux', 'Buoyant Brigadier', NULL, 6, 'Damp', 'Large', 1000, 'Its corkscrew tail acts as a propeller.Research claims that if its body could withstand the strain, it could generate over 1.21 gigawatts of power.', 'https://palworld.fandom.com/wiki/Special:FilePath/Solmora Lux.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (252, 170, 'Lapure', 'Pristine Fisticuffs', NULL, 7, 'Common', 'Small', 810, 'It uses the long, flowing fur on its hands to attract attention, always taking the utmost care to keep them maintained.Highly sensitive to dirt and meticulously clean, kicking up dust nearby will invite a very disgusted glare.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lapure.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (253, 171, 'Eidrolon', 'Wings of Freedom', NULL, 9, 'Dragon', 'Large', 300, 'A new Pal that was only recently discovered.Calm and entirely docile, it spends its time as it pleases.It is no longer bound by anything.', 'https://palworld.fandom.com/wiki/Special:FilePath/Eidrolon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (254, 171, 'Eidrolon Ignis', 'Wings of Distrust', NULL, 9, 'Dragon', 'Large', 140, 'A new Pal that was only recently discovered.It trusts nothing and no one, and its tempermental nature leads to it constantly venting its rage at the nearest target.', 'https://palworld.fandom.com/wiki/Special:FilePath/Eidrolon Ignis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (255, 172, 'Dynamoff', 'Buzzy Bundle', NULL, 6, 'Electric', 'Large', 1400, 'With so little to eat at high altitudes, it will occasionally even feast on its enemies'' brains.It is thought that groups seeking a more dependable food source descended to lower skies, ultimately diverging into Beakon.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dynamoff.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (256, 173, 'Tropicaw', 'Blooming Crooner', NULL, 6, 'Verdant', 'Large', 1350, 'While some say that it flails around to mimic flowers swaying in the wind and avoid predators, others argue that a crimson flower thrashing violently at high speeds is simply so unsettling that nothing dares approach it.', 'https://palworld.fandom.com/wiki/Special:FilePath/Tropicaw.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (257, 174, 'Flaracle', 'Self-Serving Seer', 'While in party, when the player attacks an enemy afflicted with , the enemy explodes, dealing damage equal to 40% of the player''s attack damage to nearby enemies. (Does not stack.)', 8, 'Scorching', 'Large', 390, 'It focuses its mind and reads the future through flames. Should it glimpse an inconvenient destiny, it relentlessly rerolls the prophecy until it gets a favorable result. That is why the future of Flaracle is always exceptionally bright!', 'https://palworld.fandom.com/wiki/Special:FilePath/Flaracle.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (258, 176, 'Dupin', 'Illusionist Cottontail', NULL, 8, 'Scorching', 'Large', 520, 'A copy it created might quietly replace it, leaving even the Dupin itself unsure whether it is still the original.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dupin.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (259, 177, 'Roujay', 'Pitch Black Pilferer', NULL, 8, 'Dark', 'Large', 530, 'A thief by nature, it snatches items when no one is looking.No reason to be concerned when caught in the act.Once it swiftly steals your eyes, you won’t be seeing anything anyway.', 'https://palworld.fandom.com/wiki/Special:FilePath/Roujay.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (260, 178, 'Venusa', 'Salon Shunner', NULL, 6, 'Dark', 'Large', 970, 'Whenever it''s confused, it resorts to consulting with the snakes on its head.However, since they''re all ultimately the same being, it comes to understand that nothing is understood.', 'https://palworld.fandom.com/wiki/Special:FilePath/Venusa.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (261, 179, 'Mycora', 'Cute as a Button', NULL, 7, 'Verdant', 'Large', 760, 'It views humans as nothing more than convenient parasitic hosts.The reason Mycora has taken this form is to deceive humans into lowering their guard, allowing its spores to spread more efficiently.', 'https://palworld.fandom.com/wiki/Special:FilePath/Mycora.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (262, 180, 'Loomen', 'Revealer of Truths', NULL, 7, 'Dark', 'Large', 890, 'Its lantern glows with an eerie light that lays bare the truth of the world.If that light strikes you as blinding, then you most likely have something to hide.', 'https://palworld.fandom.com/wiki/Special:FilePath/Loomen.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (263, 181, 'Wistella', 'Mantle of the Night Sky', NULL, 5, 'Dark', 'Small', 1180, 'At the end of its life, a new star appears somewhere in the skies, glowing with the weight of its memories.', 'https://palworld.fandom.com/wiki/Special:FilePath/Wistella.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (264, 182, 'Solenne', 'Veiled Dancer of Dusk', 'While in the party, increases the player''s Attack in party of different Pal species.', 9, 'Dark', 'Large', 280, 'Joy and misery come in equal measure for Solenne. Those who choose to take care of one must be prepared for what that entails.', 'https://palworld.fandom.com/wiki/Special:FilePath/Solenne.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (265, 183, 'Renjishi', 'Scorching Ovation', NULL, 8, 'Scorching', 'Large', 290, 'At a glance, its movements appear exaggerated and full of openings.Strangely, however, any opponents become overwhelmed, and become unable to look away, as if transfixed.', 'https://palworld.fandom.com/wiki/Special:FilePath/Renjishi.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (266, 184, 'Aegidron', 'Guardian of Luminous Trails', NULL, 9, 'Dragon', 'Large', 30, 'In ancient times, when means of communication were limited, the light within Aegidron''s wings was used to send simple flash signals.', 'https://palworld.fandom.com/wiki/Special:FilePath/Aegidron.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (267, 185, 'Grizzbolt', 'Claws of Lightning', 'Can be ridden. Can rapidly fire a minigun while mounted.', 6, 'Electric', 'Large', 1020, 'With a friendly smile and a hardy physique, it is docile towards one it recognizes as a partner. For reasons unexplained, its personality undergoes a drastic change when wielding a minigun.', 'https://palworld.fandom.com/wiki/Special:FilePath/Grizzbolt.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (268, 186, 'Lyleen', 'Empress of Lilies', 'When activated, the queen''s soothing graces greatly restore the player''s HP.', 8, 'Verdant', 'Huge', 240, 'A docile Pal full of love.It watches over small Pals who have lost their parents.It uses a full-power to discipline naughty Pals.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lyleen.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (269, 186, 'Lyleen Noct', 'Empress of the Abyss', 'When activated, the queen''s soothing graces greatly restore the player''s HP.', 8, 'Dark', 'Huge', 220, 'An elegant Pal full of grace. It admonishes any who are disrespectful with a painful slap. Some Pals actively seek out this punishment.', 'https://palworld.fandom.com/wiki/Special:FilePath/Lyleen Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (270, 187, 'Orserk', 'Roaring Thunder', 'While fighting together, Water Pals drop more items when defeated.', 9, 'Dragon', 'Huge', 120, 'It sends electricity into its foes'' wounds, roasting them from the inside out. Fights between Orserk end in the blink of an eye.', 'https://palworld.fandom.com/wiki/Special:FilePath/Orserk.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (271, 188, 'Faleris', 'Sentinel of Dawn', 'Can be ridden as a flying mount. While fighting together, Ice Pals drop more items when defeated.', 9, 'Scorching', 'Huge', 500, 'When it finds its prey it unleashes a whirlwind of flames, burning the entire area to ash. Faleris breath is known for its pleasing scent.', 'https://palworld.fandom.com/wiki/Special:FilePath/Faleris.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (272, 188, 'Faleris Aqua', 'Sentinel of the Tides', 'Can be ridden as a flying mount.While fighting together, Fire Pals drop more items when defeated.', 9, 'Damp', 'Huge', 450, 'When it finds its prey, it unleashes a mighty torrent, sweeping the entire area.More often than not, the prey gets swept away in the chaos, leaving one to wonder whether this truly counts as hunting.', 'https://palworld.fandom.com/wiki/Special:FilePath/Faleris Aqua.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (273, 189, 'Shadowbeak', 'Unknown Life Form', 'Can be ridden as a flying mount. Enhances Dark attacks while mounted.', 8, 'Dark', 'Huge', 550, 'Born from the depths of insanity, its very existence defies reason.Having lost all genetic ties to other Pals, one wonders if it could still even be considered a Pal.', 'https://palworld.fandom.com/wiki/Special:FilePath/Shadowbeak.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (274, 190, 'Selyne', 'Crescent of the Darkest Night', 'Can be ridden as a flying mount.Enhances Neutral and Dark attacks while mounted.', 9, 'Dark', 'Huge', 360, 'The object floating behind, resembling the moon, is said to gradually become more circular with each passing generation.No one knows what will happen when the moon is full.', 'https://palworld.fandom.com/wiki/Special:FilePath/Selyne.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (275, 191, 'Bastigor', 'King of Frostfang', 'Can be ridden.While mounted, delivers crushing blows with a Ice-forged hammer.', 9, 'Frozen', 'Large', 50, 'The sight of anything round gives it an uncontrollable urge to punch it.For Bastigor the toughest challenge, after simply living, is making a snowman.', 'https://palworld.fandom.com/wiki/Special:FilePath/Bastigor.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (276, 193, 'Silvance', 'Immortal Shade', NULL, 9, 'Verdant', 'Large', 80, 'Since ancient times, it has remained within the World Tree, continuing its vigil.What it protects, and for what purpose, Silvance does not know.After all, the World Tree will tell it everything.The spores it commands surely know who the enemy is.', 'https://palworld.fandom.com/wiki/Special:FilePath/Silvance.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (277, 194, 'Dandilord', 'Bewitching Lurker', NULL, 9, 'Verdant', 'Large', 60, 'Since ancient times, it has remained within the World Tree, continuing its vigil.What it protects, and for what purpose, Dandilord does not care.After all, the World Tree knows everything.Only the mist it wields can reveal the truth.', 'https://palworld.fandom.com/wiki/Special:FilePath/Dandilord.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (278, 195, 'Bellanoir', 'Eclipsed Siren', 'When activated, attacks targeted enemy with a powerful Nightmare Ray.', 7, 'Dark', 'Huge', 620, 'Without existing, she quietly gazed upon the world. One day, she was seized with a longing to be seen. With unbridled lust for vengeance against reality, thus was born the Eclipsed Siren.', 'https://palworld.fandom.com/wiki/Special:FilePath/Bellanoir.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (279, 195, 'Bellanoir Libero', 'Twilight Siren', 'When activated, attacks targeted enemy with a powerful Nightmare Bloom.', 7, 'Dark', 'Huge', 130, 'With her desires set loose, she was soon overwhelmed. She longed for a self to gaze upon herself. And the sisters who gazed, resenting reality, were driven into the abyss and, at last, closed their eyes.', 'https://palworld.fandom.com/wiki/Special:FilePath/Bellanoir Libero.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (280, 196, 'Xenolord', 'Invader from Space', 'Can be ridden as a flying mount.Greatly increases movement speed while flying.', 8, 'Dark', 'Large', 400, '-Destination reached. Priority: Locate entity "Supersonic Dragon" -Note: Conquest deadline exceeded by years.-Update: No conquest traces found. Naturalization confirmed. Commence elimination protocol.-Staff Memo: Refrain from forgetting or consuming critical data!', 'https://palworld.fandom.com/wiki/Special:FilePath/Xenolord.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (281, 197, 'Hartalis', 'King of Salvation', 'Can be ridden.While mounted, generates a barrier that blocks all attacks.Can triple jump while mounted.', 9, 'Common', 'Huge', 90, 'The silence is unsettling, yet strangely soothing.No one else remains. All have been delivered.O King of Salvation, carry me too into eternal stillness.-The ancient text cuts off here.', 'https://palworld.fandom.com/wiki/Special:FilePath/Hartalis.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (282, 198, 'Paladius', 'Holy Knight of Legend', 'Can be ridden. Can triple jump while mounted.', 9, 'Common', 'Huge', 180, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Paladius.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (283, 199, 'Necromus', 'Dark Knight of Legend', 'Can be ridden. Can double jump while mounted.', 9, 'Dark', 'Huge', 190, NULL, 'https://palworld.fandom.com/wiki/Special:FilePath/Necromus.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (284, 200, 'Frostallion', 'Legendary Steed of Ice', 'Can be ridden as a flying mount. Changes the player''s attack type to Ice and enhances Ice attacks while mounted.', 9, 'Frozen', 'Huge', 150, 'Guardian deity of Palpagos Island, known as the Winter Caller.In the past, when a calamity struck the land, it soared into the sky and sealed away the threat by casting the island into eternal winter.', 'https://palworld.fandom.com/wiki/Special:FilePath/Frostallion.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (285, 200, 'Frostallion Noct', 'Legendary Steed of Darkness', 'Can be ridden as a flying mount. Changes the player''s attack type to Dark and enhances Dark attacks while mounted.', 9, 'Dark', 'Huge', 110, 'Guardian deity of Palpagos Island, known as the Night Caller.In the past, when a calamity struck the land, it soared into the sky and sealed away the threat by casting the island into eternal darkness.', 'https://palworld.fandom.com/wiki/Special:FilePath/Frostallion Noct.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (286, 201, 'Neptilius', 'Legend of the Seas', 'While in team, it follows up your attacks with spear strikes.Can be ridden to travel quickly across water.While mounted, it can leap high into the air over water.', 9, 'Damp', 'Huge', 160, 'After the sealing of the calamity, a champion from Feybreak emerged.It stares out to sea, awaiting one it deems worthy.For such encounters are no coincidence—they are fate.', 'https://palworld.fandom.com/wiki/Special:FilePath/Neptilius.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (287, 202, 'Jetragon', 'Legendary Celestial Dragon', 'Can be ridden as a flying mount. Can rapidly fire a missile launcher while mounted.', 9, 'Dragon', 'Huge', 70, 'Watches over Palpagos Island from high above.When calamity returns to the land, the earth will split open, and the skies will burn.It is destined to strike down the calamity in a flash of total destruction.', 'https://palworld.fandom.com/wiki/Special:FilePath/Jetragon.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (288, 203, 'Panthalus', 'Legendary Ocean King', 'Can be ridden as a flying mount.Only 1 can be summoned to a base.While at base, it constantly patrols the skies and bombards intruders from high above.', 9, 'Damp', 'Huge', 20, 'The last of its species, keeping its sacred duty close to heart.Even should its long obligation ever be fulfilled, its cries for its mother would only be answered by a solitary echo.', 'https://palworld.fandom.com/wiki/Special:FilePath/Panthalus.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (289, 204, 'Astralym', 'Calamitous Devastation Star', 'This Pal''s abilities are still being investigated.', 9, NULL, NULL, 10, 'A shadow of its former self, this mysterious Pal descended upon the Palpagos long ago.Bringing ruin and calamity, it was sealed away for millennia until it was ultimately defeated by a certain Pal Tamer', 'https://palworld.fandom.com/wiki/Special:FilePath/Astralym.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (290, 175451001210095057, 'Ophydia', 'Pure Bloom Dragon', 'Can be ridden.While in party, the player''s attacks inflict 2. (Does not stack)', 9, 'Verdant', 'Huge', 230, 'Waters where Ophydias dwell are often filled with flowers that mimic its form. Many attempts have been made to directly propagate these blooms, but they inevitably wither the moment human hands interfere.', 'https://palworld.fandom.com/wiki/Special:FilePath/Ophydia.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (291, 1281210012100550414, 'Skutlass', 'Splashy Determined Draw', 'When activated, becomes the player''s katana (: 2600).If it does not revert to its normal form quickly, will become incapacitated.It will also become incapacitated if Iaigiri is used.', 5, 'Damp', 'Large', 1420, 'A bizarre species which temporarily separates its body and uses its bones to slice through enemies, at the risk of perishing itself upon taking too long. While unconfirmed, older individuals are said to deliberately stay separated in order to trigger their survival instincts and prolong their lifespans.', 'https://palworld.fandom.com/wiki/Special:FilePath/Skutlass.png') ON CONFLICT (id) DO NOTHING;
INSERT INTO pals (id, pal_number, name, alpha_title, partner_skill, food_consumption, egg_name, egg_size, breed_power, description, image_url) VALUES (292, 19211001100110095085, 'Shaolong', 'Water God', NULL, 9, 'Dragon', 'Huge', 40, 'Its ring is reserved for a special occasion: upon meeting its destined companion, the rings are traded, a symbol of their eternal partnership.', 'https://palworld.fandom.com/wiki/Special:FilePath/Colossal Wyrm.png') ON CONFLICT (id) DO NOTHING;